---@diagnostic disable: undefined-field, undefined-global--[[    TwichUI Unit Frames (oUF)    Provides standalone unit frames for player/target/focus/pet/ToT,    castbar, party/raid/tank headers, and boss frames.    This module is intentionally independent from ElvUI unitframe internals.]]local TwichRx = _G.TwichRx---@type TwichUIlocal T = unpack(TwichRx)---@class UnitFramesModule : AceModule, AceEvent-3.0local UnitFrames = T:NewModule("UnitFrames", "AceEvent-3.0")local CreateFrame = _G.CreateFramelocal InCombatLockdown = _G.InCombatLockdownlocal UIParent = _G.UIParentlocal UnitExists = _G.UnitExistslocal UnitClass = _G.UnitClasslocal UnitIsPlayer = _G.UnitIsPlayerlocal GetSpecialization = _G.GetSpecializationlocal GetSpecializationInfo = _G.GetSpecializationInfolocal StatusBarInterpolation = (_G.Enum and _G.Enum.StatusBarInterpolation) or _G.StatusBarInterpolationlocal RAID_CLASS_COLORS = _G.RAID_CLASS_COLORSlocal C_UnitAuras = _G.C_UnitAuraslocal math_min = math.minlocal math_max = math.maxlocal math_abs = math.abslocal STYLE_NAME = "TwichUI_Reformed_UnitFrames"UnitFrames.styleRegistered = falseUnitFrames.frames = {}UnitFrames.headers = {}UnitFrames.previewFrames = {}UnitFrames.movers = {}UnitFrames._castbarState = nillocal DEBUG_SOURCE_KEY = "unitframes"local function GetDebugConsole()    return T.Tools and T.Tools.UI and T.Tools.UI.DebugConsole or nilendlocal PREVIEW_SINGLE_UNITS = {    { key = "player", label = "Player" },    { key = "target", label = "Target" },    { key = "targettarget", label = "Target of Target" },    { key = "focus", label = "Focus" },    { key = "pet", label = "Pet" },}local function GetOUF()    -- Embedded oUF in this addon lives on the addon namespace table (Engine),    -- while some external layouts expose a global oUF. Support both.    if TwichRx and type(TwichRx) == "table" and type(TwichRx.oUF) == "table" then        return TwichRx.oUF    end    if type(_G.oUF) == "table" then        return _G.oUF    end    -- Compatibility fallback