function" then        return GetLSMTexture("TwichUI-Smooth")    end    local textureName = theme:Get("statusBarTexture") or "TwichUI-Smooth"    return GetLSMTexture(textureName)endlocal function EnsureBackdrop(frame)    if frame.TwichBackdrop then        return frame.TwichBackdrop    end    local backdrop = CreateFrame("Frame", nil, frame, "BackdropTemplate")    backdrop:SetPoint("TOPLEFT", frame, "TOPLEFT", -1, 1)    backdrop:SetPoint("BOTTOMRIGHT", frame, "BOTTOMRIGHT", 1, -1)    backdrop:SetFrameLevel(math_max(0, frame:GetFrameLevel() - 1))    backdrop:SetBackdrop({        bgFile = "Interface\\Buttons\\WHITE8x8",        edgeFile = "Interface\\Buttons\\WHITE8x8",        edgeSize = 1,    })    backdrop:SetBackdropColor(0.06, 0.07, 0.09, 0.92)    backdrop:SetBackdropBorderColor(0.24, 0.26, 0.32, 0.9)    frame.TwichBackdrop = backdrop    return backdropendlocal function BuildFrameName(unit)    if unit == "targettarget" then        return "Target of Target"    end    if unit == "pettarget" then        return "Pet Target"    end    return unit and (unit:gsub("^%l", string.upper)) or "Unit"endlocal function Round(value)    local numeric = tonumber(value) or 0    if numeric >= 0 then        return math.floor(numeric + 0.5)    end    return math.ceil(numeric - 0.5)endlocal function FormatDebugColor(color)    if type(color) ~= "table" then        return "nil"    end    return string.format("%.3f, %.3f, %.3f, %.3f",        tonumber(color[1]) or 0,        tonumber(color[2]) or 0,        tonumber(color[3]) or 0,        tonumber(color[4]) or 1)endfunction UnitFrames:LogDebug(message, shouldShow)    local console = GetDebugConsole()    if not console or type(console.Log) ~= "function" then        return false    end    return console:Log(DEBUG_SOURCE_KEY, tostring(message or ""), shouldShow)endfunction UnitFrames:LogDebugf(shouldShow, messageFormat, ...)    local console = GetDebugConsole()    if not console or type(console.Logf) ~= "function" then        return false    end    return console:Logf(DEBUG_SOURCE_KEY, shouldShow, messageFormat, ...)endfunction UnitFrames:BuildDebugReport()    local db = self:GetDB()    local playerFrame = self.frames and self.frames.player or nil    local playerPower = playerFrame and playerFrame.Power or nil    local playerBarColor = nil    local playerValue = nil    local playerMax = nil    if playerPower and playerPower.GetStatusBarColor then        local r, g, b, a = playerPower:GetStatusBarColor()        playerBarColor = { r, g, b, a }    end    if playerPower and playerPower.GetValue and playerPower.GetMinMaxValues then        playerValue = playerPower:GetValue()        local _, maxValue = playerPower:GetMinMaxValues()        playerMax = maxValue    end    local lines = {        "TwichUI Unit Frames Debug Report",        "",        string.format("enabled=%s testMode=%s lockFrames=%s smoothBars=%s",            tostring(db.enabled ~= false),            tostring(db.testMode == true),            tostring(db.lockFrames == true),            tostring(db.smoothBars ~= false)),        string.format("global.power=%s", FormatDebugColor(db.colors and db.colors.power)),        string.format("scope.singles.power=%s", FormatDebugColor(db.colors and db.colors.scopes and db.colors.scopes.singles and db.colors.scopes.singles.power)),        string.format("scope.player.power=%s", FormatDebugColor(db.colors and db.colors.scopes and db.colors.scopes.player and db.colors.scopes.player.power)),        string.format("unit.player.power=%s", FormatDebugColor(db.units and db.units.player and db.units.player.colors and db.units.player.colors.power)),        string.format("player.palette=%s", FormatDebugColor(self:GetPalette("player", "player").power)),        string.format("player.bar=%s", FormatDebugColor(playerBarColor)),        string.format("player.value=%s/%s", tostring(playerValue or "nil"), tostring(playerMax or "nil")),    }    return table.concat(lines, "\n")endfunction UnitFrames:RegisterDebugSource()    if self._debugSourceRegistered == true then        return    end    local console = GetDebugConsole()    if not console or type(console.RegisterSource) ~= "function" then        return    end    console:RegisterSource(DEBUG_SOURCE_KEY, {        title = "Unit Frames",        order = 26,        aliases = { "uf", "unitframe", "unitframes" },        maxLines = 140,        buildReport = function()            return UnitFrames:BuildDebugReport()        end,    })    self._debugSourceRegistered = trueendfunction UnitFrames:TracePlayerPowerColor(context, frame, unitKey, resolvedUnit, palette, value, maxValue)    if unitKey ~= "player" and resolvedUnit ~= "player" and frame ~= self.frames.player then        return    end    local db = self:GetDB()    local signature = table.concat({        tostring(context or "unknown"),        tostring(resolvedUnit or "nil"),        FormatDebugColor(palette and palette.power),        tostring(value or "nil"),        tostring(maxValue or "nil"),        FormatDebugColor(db.colors and db.colors.power),        FormatDebugColor(db.colors and db.colors.scopes and db.colors.scopes.singles and db.colors.scopes.singles.power),        FormatDebugColor(db.colors and db.colors.scopes and db.colors.scopes.player and db.colors.scopes.player.power),        FormatDebugColor(db.units and db.units.player and db.units.player.colors and db.units.player.colors.power),    }, "|")    if self._lastPlayerPowerDebugSignature == signature then        return    end    self._lastPlayerPowerDebugSignature = signature    self:LogDebugf(false,        "player-power context=%s resolvedUnit=%s palette=%s value=%s/%s global=%s singles=%s scopePlayer=%s unitPlayer=%s",        tostring(context or "unknown"),        tostring(resolvedUnit or "nil"),        FormatDebugColor(palette and palette.power),        tostring(value or "nil"),        tostring(maxValue or "nil"),        FormatDebugColor(db.colors and db.colors.power),        FormatDebugColor(db.colors and db.colors.scopes and db.colors.scopes.singles and db.colors.scopes.singles.power),        FormatDebugColor(db.colors and db.colors.scopes and db.colors.scopes.player and db.colors.scopes.player.power),        FormatDebugColor(db.units and db.units.player and db.units.player.colors and db.units.player.colors.power))endfunction UnitFrames:ApplyPowerBarColor(powerBar, frame, unitKey, unit, value, maxValue, context)    if not powerBar or not powerBar.SetStatusBarColor then        return    end    local resolvedUnit = ResolveFrameUnit(frame, unit)    local palette = self:GetPalette(unitKey, resolvedUnit)    powerBar:SetStatusBarColor(palette.power[1], palette.power[2], palette.power[3], 1)    self:TracePlayerPowerColor(context, frame, unitKey, resolvedUnit, palette, value, maxValue)endlocal function GetFirstHeaderChild(header)    if not header or type(header.GetChildren) ~= "function" then        return nil    end    local child = header:GetChildren()    return childendlocal function ResolveScopeByUnitKey(unitKey)    if unitKey == "partyMember" then        return "party"    end    if unitKey == "raidMember" then        return "raid"    end    if unitKey == "tankMember" then        return "tank"    end    if unitKey == "boss" or (type(unitKey) == "string" and unitKey:match("^boss")) then        return "boss"    end    return "singles"endlocal function ResolveHeaderChildUnitKey(groupKey)    if groupKey == "party" then        return "partyMember"    end    if groupKey == "raid" then        return "raidMember"    end    if groupKey == "tank" then        return "tankMember"    end    return nilendlocal function IsValidAuraUnit(unit)    if type(unit) ~= "string" or unit == "" then        return false    end    if unit == "player" or unit == "pet" or unit == "target" or unit == "focus" then        return true    end    if unit == "targettarget" or unit == "mouseover" or unit == "vehicle" then        return true    end    if unit:match("^party%d+$") or unit:match("^partypet%d+$") then        return true    end    if unit:match("^raid%d+$") or unit:match("^raidpet%d+$") then        return true    end    if unit:match("^boss%d+$") or unit:match("^arena%d+$") then        return true    end    return falseendlocal function ResolveFrameUnit(frame, explicitUnit)    if not frame then        return IsValidAuraUnit(explicitUnit) and explicitUnit or nil    end    if type(frame.GetAttribute) == "function" then        local ok, unit = pcall(frame.GetAttribute, frame, "unit")        if ok and IsValidAuraUnit(unit) then            return unit        end    end    if IsValidAuraUnit(explicitUnit) then        return explicitUnit    end    if IsValidAuraUnit(frame.unit) then        return frame.unit    end    return nilendlocal function GetUsableSize(value, fallback)    local numeric = tonumber(value)    if numeric and numeric > 1 then        return numeric    end    return fallbackendlocal function ResolveHeaderChildUnitKey(groupKey)    if groupKey == "party" then        return "partyMember"    end    if groupKey == "raid" then        return "raidMember"    end    if groupKey == "tank" then        return "tankMember"    end    return nilendlocal function ResolveFrameUnit(frame, explicitUnit)    if not frame then        return IsValidAuraUnit(explicitUnit) and explicitUnit or nil    end    if type(frame.GetAttribute) == "function" then        local ok, unit = pcall(frame.GetAttribute, frame, "unit")        if ok and IsValidAuraUnit(unit) then            return unit        end    end    if IsValidAuraUnit(explicitUnit) then        return explicitUnit    end    if IsValidAuraUnit(frame.unit) then        return frame.unit    end    return nilendlocal function GetUsableSize(value, fallback)    local numeric = tonumber(value)    if numeric and numeric > 1 then        return numeric    end    return fallbackendlocal function ResolveCastbarScopeByUnitKey(unitKey)    if unitKey == "partyMember" or unitKey == "tankMember" then        return "party"    end    if unitKey == "raidMember" then        return "raid"    end    if unitKey == "boss" or (type(unitKey) == "string" and unitKey:match("^boss")) then        return "boss"    end    return "target"endlocal function ResolveOutlineFlags(mode)    local normalized = tostring(mode or "OUTLINE")    if normalized == "NONE" then        return nil    end    if normalized == "THICKOUTLINE" then        return "THICKOUTLINE"    end    if normalized == "MONOCHROME" then        return "MONOCHROME"    end    if normalized == "MONOCHROMEOUTLINE" then        return "OUTLINE, MONOCHROME"    end    if normalized == "MONOCHROMETHICKOUTLINE" then    local scopeColors = db.colors.scopes[resolvedScope]    local legacyScopeColors = nil    local unitColors = nil    local unitHealth = nil    if unitKey and unitKey ~= "partyMember" and unitKey ~= "raidMember" and unitKey ~= "tankMember" then        db.units = db.units or {}        db.units[unitKey] = db.units[unitKey] or {}        unitColors = db.units[unitKey].colors or nil        unitHealth = db.units[unitKey].healthColor or nil        legacyScopeColors = db.colors.scopes[unitKey] or nil    end    local palette = {        health = CopyColor(scopeColors.health or db.colors.health or GetThemeColor("successColor", { 0.34, 0.84, 0.54, 1 })),        power = CopyColor((legacyScopeColors and legacyScopeColors.power) or scopeColors.power or db.colors.power or GetThemeColor("primaryColor", { 0.10, 0.72, 0.74, 1 })),        cast = CopyColor((legacyScopeColors and legacyScopeColors.cast) or scopeColors.cast or db.colors.cast or GetThemeColor("accentColor", { 0.96, 0.76, 0.24, 1 })),        background = CopyColor((legacyScopeColors and legacyScopeColors.background) or scopeColors.background or db.colors.background or GetThemeColor("backgroundColor", { 0.05, 0.06, 0.08, 1 })),        border = CopyColor((legacyScopeColors and legacyScopeColors.border) or scopeColors.border or db.colors.border or GetThemeColor("borderColor", { 0.24, 0.26, 0.32, 1 })),    }    if unitColors then        if type(unitColors.power) == "table" then palette.power = CopyColor(unitColors.power) end        if type(unitColors.cast) == "table" then palette.cast = CopyColor(unitColors.cast) end        if type(unitColors.background) == "table" then palette.background = CopyColor(unitColors.background) end        if type(unitColors.border) == "table" then palette.border = CopyColor(unitColors.border) end    end    local healthScope = (unitKey and db.healthColorByScope[unitKey]) or db.healthColorByScope[resolvedScope] or {}    local mode = (unitHealth and unitHealth.mode and unitHealth.mode ~= "inherit" and unitHealth.mode)        or healthScope.mode        or (db.useClassColor == true and "class" or "theme")    elseif classToken == "MAGE" then        dispelTypes.Curse = true    elseif classToken == "MONK" then        dispelTypes.Disease = true        dispelTypes.Poison = true        if specID == 270 then            dispelTypes.Magic = true        end    elseif classToken == "PALADIN" then        dispelTypes.Disease = true        dispelTypes.Magic = true        dispelTypes.Poison = true    elseif classToken == "PRIEST" then        dispelTypes.Disease = true        dispelTypes.Magic = true    elseif classToken == "SHAMAN" then        dispelTypes.Curse = true        if specID == 264 then            dispelTypes.Magic = true        end    end    cachedDispelClass = classToken    cachedDispelSpec = specID    cachedDispelTypes = dispelTypes    return dispelTypesendlocal function NormalizeDispelName(dispelName)    if dispelName == "" then        return "Enrage"    end    return dispelNameendlocal function AuraMatchesDisplayMode(mode, data)    if not data then        return false    end    if mode == "DISPELLABLE" or mode == "DISPELLABLE_OR_BOSS" then        if data.isHarmfulAura ~= true then            return false        end        local dispelTypes = GetPlayerDispelTypes()        local dispelName = NormalizeDispelName(data.dispelName)        local canDispel = dispelName and dispelTypes[dispelName] == true        if mode == "DISPELLABLE" then            return canDispel == true        end        return canDispel == true or data.isBossAura == true    end    return trueendfunction UnitFrames:GetOptions()    if frame.Power then        self:ApplyPowerBarColor(frame.Power, frame, unitKey, frame and frame.unit, nil, nil, "ApplyFrameColors")    endfunction UnitFrames:GetDB()    local options = self:GetOptions()    if options and type(options.GetDB) == "function" then        return options:GetDB()    end    return {}endfunction UnitFrames:GetUnitSettings(unit)    local db = self:GetDB()    db.units = db.units or {}    db.units[unit] = db.units[unit] or {}    return db.units[unit]endfunction UnitFrames:GetGroupSettings(group)    local db = self:GetDB()    db.groups = db.groups or {}    db.groups[group] = db.groups[group] or {}    return db.groups[group]endfunction UnitFrames:GetLayoutSettings(key)    local db = self:GetDB()    db.layout = db.layout or {}    db.layout[key] = db.layout[key] or {}    return db.layout[key]endfunction UnitFrames:GetPalette(scopeOrUnitKey, unit)    local db = self:GetDB()    db.colors = db.colors or {}    db.colors.scopes = db.colors.scopes or {}    local unitKey = nil    local resolvedScope = scopeOrUnitKey or "singles"    if resolvedScope ~= "singles" and resolvedScope ~= "party" and resolvedScope ~= "raid"        and resolvedScope ~= "tank" and resolvedScope ~= "boss" then        unitKey = resolvedScope        resolvedScope = ResolveScopeByUnitKey(unitKey)    end    db.colors.scopes[resolvedScope] = db.colors.scopes[resolvedScope] or {}    db.healthColorByScope = db.healthColorByScope or {}    local scopeColors = db.colors.scopes[resolvedScope]    local unitColors = nil    local unitHealth = nil    if unitKey and unitKey ~= "partyMember" and unitKey ~= "raidMember" and unitKey ~= "tankMember" then        db.units = db.units or {}        db.units[unitKey] = db.units[unitKey] or {}        unitColors = db.units[unitKey].colors or nil        unitHealth = db.units[unitKey].healthColor or nil    end    local palette = {        health = CopyColor(scopeColors.health or db.colors.health or GetThemeColor("successColor", { 0.34, 0.84, 0.54, 1 })),        power = CopyColor(scopeColors.power or db.colors.power or GetThemeColor("primaryColor", { 0.10, 0.72, 0.74, 1 })),        cast = CopyColor(scopeColors.cast or db.colors.cast or GetThemeColor("accentColor", { 0.96, 0.76, 0.24, 1 })),        background = CopyColor(scopeColors.background or db.colors.background or GetThemeColor("backgroundColor", { 0.05, 0.06, 0.08, 1 })),        border = CopyColor(scopeColors.border or db.colors.border or GetThemeColor("borderColor", { 0.24, 0.26, 0.32, 1 })),    }    if unitColors then        if type(unitColors.power) == "table" then palette.power = CopyColor(unitColors.power) end        if type(unitColors.cast) == "table" then palette.cast = CopyColor(unitColors.cast) end        if type(unitColors.background) == "table" then palette.background = CopyColor(unitColors.background) end        if type(unitColors.border) == "table" then palette.border = CopyColor(unitColors.border) end    end    local healthScope = (unitKey and db.healthColorByScope[unitKey]) or db.healthColorByScope[resolvedScope] or {}    local mode = (unitHealth and unitHealth.mode and unitHealth.mode ~= "inherit" and unitHealth.mode)        or healthScope.mode        or (db.useClassColor == true and "class" or "theme")    if mode == "custom" then        if unitHealth and type(unitHealth.color) == "table" then            palette.health = CopyColor(unitHealth.color)        elseif type(healthScope.color) == "table" then            palette.health = CopyColor(healthScope.color)        end    elseif mode == "class" then        local classToken = nil        if unit and UnitIsPlayer and UnitIsPlayer(unit) then            _, classToken = UnitClass(unit)        elseif unitKey == "player" then            _, classToken = UnitClass("player")        end        local classColor = (_G.CUSTOM_CLASS_COLORS or RAID_CLASS_COLORS)[classToken or ""]        if classColor then            palette.health = { classColor.r, classColor.g, classColor.b, 1 }        end    end    return paletteendfunction UnitFrames:ApplyStatusBarTexture(frame)    local db = self:GetDB()    local textureName = db.texture    local texture = (textureName and textureName ~= "") and GetLSMTexture(textureName) or GetThemeTexture()    if frame.Health and frame.Health.SetStatusBarTexture then        frame.Health:SetStatusBarTexture(texture)    end    if frame.Power and frame.Power.SetStatusBarTexture then        frame.Power:SetStatusBarTexture(texture)    end    if frame.Castbar and frame.Castbar.SetStatusBarTexture then        frame.Castbar:SetStatusBarTexture(texture)    end    if frame.ClassPower then        for i = 1, #frame.ClassPower do            local bar = frame.ClassPower[i]            if bar and bar.SetStatusBarTexture then                bar:SetStatusBarTexture(texture)            end        end    endendfunction UnitFrames:ApplyFrameColors(frame, unitKey)    local palette = self:GetPalette(unitKey, ResolveFrameUnit(frame, frame and frame.unit))    local backdrop = EnsureBackdrop(frame)    backdrop:SetBackdropColor(palette.background[1], palette.background[2], palette.background[3], 0.9)    backdrop:SetBackdropBorderColor(palette.border[1], palette.border[2], palette.border[3], 0.9)    if frame.Health and frame.Health.SetStatusBarColor then        frame.Health:SetStatusBarColor(palette.health[1], palette.health[2], palette.health[3], 1)    end    if frame.Power and frame.Power.SetStatusBarColor then        frame.Power:SetStatusBarColor(palette.power[1], palette.power[2], palette.power[3], 1)    end    if frame.Castbar and frame.Castbar.SetStatusBarColor then        frame.Castbar:SetStatusBarColor(palette.cast[1], palette.cast[2], palette.cast[3], 1)    endendfunction UnitFrames:ApplyClassBarColors(frame, colorObject)    if not frame or not frame.ClassPower then        return    end    local cfg = self:GetDB().classBar or {}    local r, g, b, a = 1, 1, 1, 1    if cfg.useCustomColor == true and type(cfg.color) == "table" then        r = cfg.color[1] or 1        g = cfg.color[2] or 1        b = cfg.color[3] or 1        a = cfg.color[4] or 1    elseif colorObject and type(colorObject.GetRGB) == "function" then        r, g, b = colorObject:GetRGB()    else        local palette = self:GetPalette("player", "player")        r = palette.power[1] or 1        g = palette.power[2] or 1        b = palette.power[3] or 1    end    local backdropAlpha = math_max(0.16, (a or 1) * 0.28)    local borderAlpha = math_max(0.45, (a or 1) * 0.65)    for index = 1, #frame.ClassPower do        local bar = frame.ClassPower[index]        if bar and bar.SetStatusBarColor then            bar:SetStatusBarColor(r, g, b, a)            if bar.SetBackdropColor then                bar:SetBackdropColor(r, g, b, backdropAlpha)            end            if bar.SetBackdropBorderColor then                bar:SetBackdropBorderColor(r, g, b, borderAlpha)            end        end    endendfunction UnitFrames:ApplyFontObject(fontString, size, explicitFontName, textStyle)    if not fontString then        return    end    local LSM = T.Libs and T.Libs.LSM    local theme = GetThemeModule()    local fontName = explicitFontName or (theme and theme.Get and theme:Get("globalFont")) or "__default"    local path = nil    if LSM and type(LSM.Fetch) == "function" and fontName and fontName ~= "__default" then        local ok, fetched = pcall(LSM.Fetch, LSM, "font", fontName)        if ok and type(fetched) == "string" and fetched ~= "" then            path = fetched        end    end    if not path then        path = _G.STANDARD_TEXT_FONT    end    fontString:SetFont(path, size or 11, ResolveOutlineFlags(textStyle and textStyle.outlineMode))    if textStyle and textStyle.shadowEnabled == true then        local shadowColor = type(textStyle.shadowColor) == "table" and textStyle.shadowColor or { 0, 0, 0, 0.85 }        fontString:SetShadowColor(            shadowColor[1] or 0,            shadowColor[2] or 0,            shadowColor[3] or 0,            shadowColor[4] or 0.85        )        fontString:SetShadowOffset(            tonumber(textStyle.shadowOffsetX) or 1,            tonumber(textStyle.shadowOffsetY) or -1        )    else        fontString:SetShadowColor(0, 0, 0, 0)        fontString:SetShadowOffset(0, 0)    endendfunction UnitFrames:GetTextConfig()    local db = self:GetDB()    db.text = db.text or {}    if db.text.nameFormat == nil then db.text.nameFormat = "full" end    if db.text.healthFormat == nil then db.text.healthFormat = "percent" end    if db.text.powerFormat == nil then db.text.powerFormat = "percent" end    if db.text.nameFontSize == nil then db.text.nameFontSize = 11 end    if db.text.healthFontSize == nil then db.text.healthFontSize = 10 end    if db.text.powerFontSize == nil then db.text.powerFontSize = 9 end    if db.text.fontName == nil then db.text.fontName = nil end    if db.text.outlineMode == nil then db.text.outlineMode = "OUTLINE" end    if db.text.shadowEnabled == nil then db.text.shadowEnabled = false end    if db.text.shadowColor == nil then db.text.shadowColor = { 0, 0, 0, 0.85 } end    if db.text.shadowOffsetX == nil then db.text.shadowOffsetX = 1 end    if db.text.shadowOffsetY == nil then db.text.shadowOffsetY = -1 end    if db.text.customNameTag == nil then db.text.customNameTag = nil end    if db.text.customHealthTag == nil then db.text.customHealthTag = nil end    if db.text.customPowerTag == nil then db.text.customPowerTag = nil end    return db.textendfunction UnitFrames:GetTextConfigFor(unitKey)    local root = self:GetTextConfig()    local scope = ResolveScopeByUnitKey(unitKey)    root.scopes = root.scopes or {}    root.scopes[scope] = root.scopes[scope] or {}    local scoped = root.scopes[scope]    if scoped.nameFormat == nil then scoped.nameFormat = root.nameFormat or "full" end    if scoped.healthFormat == nil then scoped.healthFormat = root.healthFormat or "percent" end    if scoped.powerFormat == nil then scoped.powerFormat = root.powerFormat or "percent" end    if scoped.nameFontSize == nil then scoped.nameFontSize = root.nameFontSize or 11 end    if scoped.healthFontSize == nil then scoped.healthFontSize = root.healthFontSize or 10 end    if scoped.powerFontSize == nil then scoped.powerFontSize = root.powerFontSize or 9 end    if scoped.fontName == nil then scoped.fontName = root.fontName end    if scoped.outlineMode == nil then scoped.outlineMode = root.outlineMode or "OUTLINE" end    if scoped.shadowEnabled == nil then scoped.shadowEnabled = root.shadowEnabled == true end    if scoped.shadowColor == nil then scoped.shadowColor = root.shadowColor or { 0, 0, 0, 0.85 } end    if scoped.shadowOffsetX == nil then scoped.shadowOffsetX = root.shadowOffsetX or 1 end    if scoped.shadowOffsetY == nil then scoped.shadowOffsetY = root.shadowOffsetY or -1 end    if scoped.customNameTag == nil then scoped.customNameTag = root.customNameTag end    if scoped.customHealthTag == nil then scoped.customHealthTag = root.customHealthTag end    if scoped.customPowerTag == nil then scoped.customPowerTag = root.customPowerTag end    if scoped.namePoint == nil then scoped.namePoint = scoped.nameJustify or "LEFT" end    if scoped.nameRelativePoint == nil then scoped.nameRelativePoint = scoped.namePoint end    if scoped.nameOffsetX == nil then scoped.nameOffsetX = 4 end    if scoped.nameOffsetY == nil then scoped.nameOffsetY = 0 end    if scoped.healthPoint == nil then scoped.healthPoint = scoped.healthJustify or "RIGHT" end    if scoped.healthRelativePoint == nil then scoped.healthRelativePoint = scoped.healthPoint end    if scoped.healthOffsetX == nil then scoped.healthOffsetX = -4 end    if scoped.healthOffsetY == nil then scoped.healthOffsetY = 0 end    if scoped.powerPoint == nil then scoped.powerPoint = scoped.powerJustify or "RIGHT" end    if scoped.powerRelativePoint == nil then scoped.powerRelativePoint = scoped.powerPoint end    if scoped.powerOffsetX == nil then scoped.powerOffsetX = -4 end    if scoped.powerOffsetY == nil then scoped.powerOffsetY = 0 end    local merged = {        nameFormat = scoped.nameFormat,        healthFormat = scoped.healthFormat,        powerFormat = scoped.powerFormat,        nameFontSize = scoped.nameFontSize,        healthFontSize = scoped.healthFontSize,        powerFontSize = scoped.powerFontSize,        fontName = scoped.fontName,        outlineMode = scoped.outlineMode,        shadowEnabled = scoped.shadowEnabled,        shadowColor = scoped.shadowColor,        shadowOffsetX = scoped.shadowOffsetX,        shadowOffsetY = scoped.shadowOffsetY,        customNameTag = scoped.customNameTag,        customHealthTag = scoped.customHealthTag,        customPowerTag = scoped.customPowerTag,        namePoint = scoped.namePoint,        nameRelativePoint = scoped.nameRelativePoint,        nameOffsetX = scoped.nameOffsetX,        nameOffsetY = scoped.nameOffsetY,        healthPoint = scoped.healthPoint,        healthRelativePoint = scoped.healthRelativePoint,        healthOffsetX = scoped.healthOffsetX,        healthOffsetY = scoped.healthOffsetY,        powerPoint = scoped.powerPoint,        powerRelativePoint = scoped.powerRelativePoint,        powerOffsetX = scoped.powerOffsetX,        powerOffsetY = scoped.powerOffsetY,    }    -- Per-unit overrides (only for directly addressed units, not group member types).    if unitKey ~= "partyMember" and unitKey ~= "raidMember" and unitKey ~= "tankMember" then        local db = self:GetDB()        db.units = db.units or {}        db.units[unitKey] = db.units[unitKey] or {}        local unitText = type(db.units[unitKey].text) == "table" and db.units[unitKey].text or nil        if unitText then            for key, value in pairs(unitText) do                if value ~= nil then                    merged[key] = value                end            end        end    end    return mergedendfunction UnitFrames:GetAuraConfigFor(unitKey)    local db = self:GetDB()    db.auras = db.auras or {}    db.auras.scopes = db.auras.scopes or {}    local scope = ResolveScopeByUnitKey(unitKey)    db.auras.scopes[scope] = db.auras.scopes[scope] or {}    local scoped = db.auras.scopes[scope]    local merged = {        enabled = scoped.enabled,        maxIcons = scoped.maxIcons,        iconSize = scoped.iconSize,        spacing = scoped.spacing,        yOffset = scoped.yOffset,        filter = scoped.filter,        onlyMine = scoped.onlyMine,        barMode = scoped.barMode,        barHeight = scoped.barHeight,    }    if merged.enabled == nil then merged.enabled = true end    if merged.maxIcons == nil then merged.maxIcons = 8 end    if merged.iconSize == nil then merged.iconSize = 18 end    if merged.spacing == nil then merged.spacing = 2 end    if merged.yOffset == nil then merged.yOffset = 6 end    if merged.filter == nil then merged.filter = "ALL" end    if merged.onlyMine == nil then merged.onlyMine = false end    if merged.barMode == nil then merged.barMode = false end    if merged.barHeight == nil then merged.barHeight = 14 end    if scope == "singles" then        db.units = db.units or {}        db.units[unitKey] = db.units[unitKey] or {}        local unitAuras = type(db.units[unitKey].auras) == "table" and db.units[unitKey].auras or nil        if unitAuras then            for key, value in pairs(unitAuras) do                if value ~= nil then                    merged[key] = value                end            end        end    end    return mergedendlocal function BuildHealthTag(format, customTag)    if format == "custom" and type(customTag) == "string" and customTag ~= "" then        return customTag    end    if format == "current" then        return "[curhp]"    end    if format == "currentPercent" then        return "[curhp] [perhp<$%]"    end    if format == "missing" then        return "[missinghp]"    end    return "[perhp<$%]"endlocal function BuildPowerTag(format, customTag)    if format == "custom" and type(customTag) == "string" and customTag ~= "" then        return customTag    end    if format == "current" then        return "[curpp]"    end    if format == "currentPercent" then        return "[curpp] [perpp<$%]"    end    if format == "missing" then        return "[missingpp]"    end    return "[perpp<$%]"endlocal function BuildNameTag(format, customTag)    if format == "custom" and type(customTag) == "string" and customTag ~= "" then        return customTag    end    if format == "short" then        return "[name(8)]"    end    return "[name]"endfunction UnitFrames:ApplyTextTags(frame, unitKey)    if not frame or type(frame.Tag) ~= "function" or type(frame.Untag) ~= "function" then        return    end    local text = self:GetTextConfigFor(unitKey)    local nameTag = BuildNameTag(text.nameFormat, text.customNameTag)    local healthTag = BuildHealthTag(text.healthFormat, text.customHealthTag)    local powerTag = BuildPowerTag(text.powerFormat, text.customPowerTag)    if frame.Name then        frame:Untag(frame.Name)        frame:Tag(frame.Name, nameTag)        if frame.Name.UpdateTag then            frame.Name:UpdateTag()        end    end    if frame.HealthValue then        frame:Untag(frame.HealthValue)        frame:Tag(frame.HealthValue, healthTag)        if frame.HealthValue.UpdateTag then            frame.HealthValue:UpdateTag()        end    end    if frame.PowerValue then        frame:Untag(frame.PowerValue)        frame:Tag(frame.PowerValue, powerTag)        if frame.PowerValue.UpdateTag then            frame.PowerValue:UpdateTag()        end    endendfunction UnitFrames:ApplyFrameFonts(frame, unitKey)    local text = self:GetTextConfigFor(unitKey)    if frame.Name then        self:ApplyFontObject(frame.Name, Clamp(text.nameFontSize or 11, 6, 28), text.fontName, text)    end    if frame.HealthValue then        self:ApplyFontObject(frame.HealthValue, Clamp(text.healthFontSize or 10, 6, 28), text.fontName, text)    end    if frame.PowerValue then        self:ApplyFontObject(frame.PowerValue, Clamp(text.powerFontSize or 9, 6, 28), text.fontName, text)    endendfunction UnitFrames:ApplyAuraSettings(frame, unitKey)    if not frame or not frame.Auras then return end    local aura = self:GetAuraConfigFor(unitKey)    local maxIcons = math_max(1, math.floor(tonumber(aura.maxIcons) or 8))    local iconSize = Clamp(aura.iconSize or 18, 10, 40)    local spacing = Clamp(aura.spacing or 2, 0, 8)    local yOff = Clamp(aura.yOffset or 6, -20, 30)    local filter = aura.filter or "ALL"    frame.Auras.onlyShowPlayer = aura.onlyMine == true    frame.Auras.twichFilterMode = filter    frame.Auras.showDebuffType = true    frame.Auras.FilterAura = function(element, _, data)        if element.onlyShowPlayer == true and data.isPlayerAura ~= true then            return false        end        return AuraMatchesDisplayMode(element.twichFilterMode, data)    end    if aura.barMode == true then        -- Bar mode: zero out the icon grid (PostUpdate still fires when UNIT_AURA happens).        frame.Auras.num = 0        frame.Auras.numTotal = 0        frame.Auras.numBuffs = 0        frame.Auras.numDebuffs = 0        frame.Auras:SetShown(false)        local bars = self:EnsureAuraBarsContainer(frame)        bars:ClearAllPoints()        bars:SetPoint("BOTTOMLEFT", frame, "TOPLEFT", 0, yOff)        bars:SetShown(aura.enabled ~= false)        self:RefreshAuraBarsForFrame(frame, unitKey)    else        -- Icon mode.        if frame.AuraBars then frame.AuraBars:Hide() end        if filter == "HELPFUL" then            frame.Auras.numBuffs = maxIcons            frame.Auras.numDebuffs = 0            frame.Auras.numTotal = maxIcons            frame.Auras.buffFilter = "HELPFUL"            frame.Auras.debuffFilter = nil        elseif filter == "HARMFUL" or filter == "DISPELLABLE" or filter == "DISPELLABLE_OR_BOSS" then            frame.Auras.numBuffs = 0            frame.Auras.numDebuffs = maxIcons            frame.Auras.numTotal = maxIcons            frame.Auras.buffFilter = nil            frame.Auras.debuffFilter = "HARMFUL"        else -- "ALL"            frame.Auras.numBuffs = nil            frame.Auras.numDebuffs = nil            frame.Auras.numTotal = maxIcons            frame.Auras.buffFilter = nil            frame.Auras.debuffFilter = nil        end        frame.Auras.num = maxIcons        frame.Auras.size = iconSize        frame.Auras.spacing = spacing        frame.Auras.needFullUpdate = true        frame.Auras:SetShown(aura.enabled ~= false)        frame.Auras:ClearAllPoints()        frame.Auras:SetPoint("BOTTOMLEFT", frame, "TOPLEFT", 0, yOff)        frame.Auras:SetHeight(iconSize)        frame.Auras:SetWidth((iconSize * maxIcons) + (spacing * math_max(0, maxIcons - 1)))        if frame.Auras.ForceUpdate then            local resolvedUnit = ResolveFrameUnit(frame, frame.unit)            if resolvedUnit then                frame.unit = resolvedUnit                frame.Auras:ForceUpdate()            else                frame.Auras:Hide()            end        end    endendfunction UnitFrames:ApplyTagVisibility(frame)    local db = self:GetDB()    local showHealth = db.showHealthText ~= false    local showPower = db.showPowerText ~= false    if frame.HealthValue then        frame.HealthValue:SetShown(showHealth)    end    if frame.PowerValue then        frame.PowerValue:SetShown(showPower)    endendlocal function PointToJustify(point)    local resolved = tostring(point or "CENTER")    if resolved:find("LEFT") then        return "LEFT"    end    if resolved:find("RIGHT") then        return "RIGHT"    end    return "CENTER"endlocal function AnchorText(fontString, parent, point, relativePoint, offsetX, offsetY, width)    if not fontString or not parent then        return    end    fontString:ClearAllPoints()    fontString:SetPoint(point or "CENTER", parent, relativePoint or point or "CENTER", offsetX or 0, offsetY or 0)    if width and fontString.SetWidth then        fontString:SetWidth(width)    end    fontString:SetJustifyH(PointToJustify(point))endfunction UnitFrames:ApplyTextPositions(frame, unitKey)    if not frame then return end    local text = self:GetTextConfigFor(unitKey)    local healthWidth = GetUsableSize(frame.Health and frame.Health:GetWidth(), GetUsableSize(frame:GetWidth(), 120))    local powerWidth = GetUsableSize(frame.Power and frame.Power:GetWidth(), GetUsableSize(frame:GetWidth(), 120))    if frame.Name and frame.Health then        AnchorText(            frame.Name,            frame.Health,            text.namePoint or "LEFT",            text.nameRelativePoint or text.namePoint or "LEFT",            tonumber(text.nameOffsetX) or 4,            tonumber(text.nameOffsetY) or 0,            math_max(20, healthWidth - 16)        )    end    if frame.HealthValue and frame.Health then        AnchorText(            frame.HealthValue,            frame.Health,            text.healthPoint or "RIGHT",            text.healthRelativePoint or text.healthPoint or "RIGHT",            tonumber(text.healthOffsetX) or -4,            tonumber(text.healthOffsetY) or 0,            math_max(16, healthWidth - 8)        )    end    if frame.PowerValue and frame.Power then        AnchorText(            frame.PowerValue,            frame.Power,            text.powerPoint or "RIGHT",            text.powerRelativePoint or text.powerPoint or "RIGHT",            tonumber(text.powerOffsetX) or -4,            tonumber(text.powerOffsetY) or 0,            math_max(16, powerWidth - 8)        )    endendfunction UnitFrames:ApplySmoothBarValue(bar, value, maxValue)    if not bar or not bar.SetMinMaxValues or not bar.SetValue then        return    end    local smoothingMethod = nil    if StatusBarInterpolation then        if self:GetDB().smoothBars ~= false then            smoothingMethod = StatusBarInterpolation.ExponentialEaseOut        else            smoothingMethod = StatusBarInterpolation.Immediate        end    end    bar.smoothing = smoothingMethod    local okMinMax = pcall(bar.SetMinMaxValues, bar, 0, maxValue)    if not okMinMax then        pcall(bar.SetMinMaxValues, bar, 0, 1)    end    if smoothingMethod then        local okSmoothed = pcall(bar.SetValue, bar, value, smoothingMethod)        if okSmoothed then            return        end    end    pcall(bar.SetValue, bar, value)endfunction UnitFrames:GetCastbarSmoothingMethod()    if not StatusBarInterpolation then        return nil    end    if self:GetDB().smoothBars == false then        return StatusBarInterpolation.Immediate    end    return StatusBarInterpolation.Linear or StatusBarInterpolation.ExponentialEaseOutendfunction UnitFrames:ApplyCastbarValue(bar, value, maxValue)    if not bar or not bar.SetMinMaxValues or not bar.SetValue then        return    end    local smoothingMethod = self:GetCastbarSmoothingMethod()    bar.smoothing = smoothingMethod    local okMinMax = pcall(bar.SetMinMaxValues, bar, 0, maxValue)    if not okMinMax then        pcall(bar.SetMinMaxValues, bar, 0, 1)    end    if smoothingMethod then        local okSmoothed = pcall(bar.SetValue, bar, value, smoothingMethod)        if okSmoothed then            return        end    end    pcall(bar.SetValue, bar, value)endfunction UnitFrames:StopSmoothBar(bar)    if not bar then        return    end    bar.smoothing = nilend-- Updates target and mouseover highlight overlays on a unit frame.function UnitFrames:UpdateUnitHighlights(frame)    if not frame then return end    local unit = frame.unit    local db = self:GetDB()    local highlights = db.highlights or {}    if frame.TwichTargetHighlight then        local isTarget = unit and UnitExists and pcall(UnitExists, unit)            and _G.UnitIsUnit and pcall(_G.UnitIsUnit, unit, "target")        -- simpler, taint-safe approach: just check via pcall        local okTarget, targetMatch = false, false        if unit then            okTarget, targetMatch = pcall(_G.UnitIsUnit, unit, "target")        end        if highlights.showTarget ~= false and okTarget and targetMatch then            local c = highlights.targetColor or { 1.0, 0.82, 0.0, 0.9 }            frame.TwichTargetHighlight:SetBackdropBorderColor(c[1] or 1, c[2] or 0.82, c[3] or 0, c[4] or 0.9)            frame.TwichTargetHighlight:Show()        else            frame.TwichTargetHighlight:Hide()        end    end    if frame.TwichMouseoverHighlight then        if highlights.showMouseover ~= false and frame.isHovering then            local c = highlights.mouseoverColor or { 1.0, 1.0, 1.0, 0.08 }            frame.TwichMouseoverHighlight:SetBackdropColor(c[1] or 1, c[2] or 1, c[3] or 1, c[4] or 0.08)            frame.TwichMouseoverHighlight:Show()        else            frame.TwichMouseoverHighlight:Hide()        end    endendfunction UnitFrames:OnTargetChanged()    for _, frame in pairs(self.frames) do        if frame and frame.TwichTargetHighlight then            self:UpdateUnitHighlights(frame)        end    endendfunction UnitFrames:OnMouseoverChanged()    for _, frame in pairs(self.frames) do        if frame and frame.TwichMouseoverHighlight then            self:UpdateUnitHighlights(frame)        end    endendfunction UnitFrames:ApplyUnitFrameSize(frame, settings)    local width = Clamp(settings.width or 220, 80, 600)    local height = Clamp(settings.height or 42, 16, 180)    frame:SetSize(width, height)    if frame.Health and frame.Power then        local powerHeight = settings.showPower == false and 0 or Clamp(settings.powerHeight or 10, 4, 32)        local detachedPower = settings.powerDetached == true        frame.Health:ClearAllPoints()        frame.Power:ClearAllPoints()        if powerHeight > 0 then            frame.Power:Show()            frame.Power:SetHeight(powerHeight)            if detachedPower then                frame.Power:SetWidth(Clamp(settings.powerWidth or width, 40, 600))                frame.Power:SetPoint(                    settings.powerPoint or "TOPLEFT",                    frame,                    settings.powerRelativePoint or "BOTTOMLEFT",                    tonumber(settings.powerOffsetX) or 0,                    tonumber(settings.powerOffsetY) or -1                )                frame.Health:SetAllPoints(frame)            else                frame.Power:SetPoint("BOTTOMLEFT", frame, "BOTTOMLEFT", 0, 0)                frame.Power:SetPoint("BOTTOMRIGHT", frame, "BOTTOMRIGHT", 0, 0)                frame.Health:SetPoint("TOPLEFT", frame, "TOPLEFT", 0, 0)                frame.Health:SetPoint("TOPRIGHT", frame, "TOPRIGHT", 0, 0)                frame.Health:SetPoint("BOTTOM", frame.Power, "TOP", 0, 1)            end        else            frame.Power:Hide()            frame.Power:SetPoint("BOTTOMLEFT", frame, "BOTTOMLEFT", 0, 0)            frame.Power:SetPoint("BOTTOMRIGHT", frame, "BOTTOMRIGHT", 0, 0)            frame.Health:SetAllPoints(frame)        end    endendfunction UnitFrames:ApplySingleFrameSettings(frame, unitKey)    local settings = nil    if unitKey and unitKey:match("^boss%d+$") then        settings = self:GetUnitSettings("boss")    elseif unitKey == "partyMember" then        local group = self:GetGroupSettings("party")        settings = {            enabled = group.enabled,            width = group.width,            height = group.height,            showPower = true,            powerHeight = 8,        }    elseif unitKey == "raidMember" then        local group = self:GetGroupSettings("raid")        settings = {            enabled = group.enabled,            width = group.width,            height = group.height,            showPower = true,            powerHeight = 7,        }    elseif unitKey == "tankMember" then        local group = self:GetGroupSettings("tank")        settings = {            enabled = group.enabled,            width = group.width,            height = group.height,            showPower = true,            powerHeight = 8,        }    else        settings = self:GetUnitSettings(unitKey)    end    local layout = self:GetLayoutSettings(unitKey)    local resolvedUnit = ResolveFrameUnit(frame, frame and frame.unit)    if resolvedUnit then        frame.unit = resolvedUnit    end    self:ApplyUnitFrameSize(frame, settings)    if not frame.isHeaderChild then        frame:ClearAllPoints()        frame:SetPoint(            layout.point or "BOTTOM",            UIParent,            layout.relativePoint or "BOTTOM",            tonumber(layout.x) or 0,            tonumber(layout.y) or 0        )    end    local db = self:GetDB()    frame:SetScale(Clamp(db.scale or 1, 0.6, 1.6))    frame:SetAlpha(Clamp(db.frameAlpha or 1, 0.15, 1))    local shouldShow = settings.enabled ~= false    if db.testMode == true then        shouldShow = false    end    frame:SetShown(shouldShow)    self:ApplyStatusBarTexture(frame)    self:ApplyFrameColors(frame, unitKey)    self:ApplyFrameFonts(frame, unitKey)    self:ApplyTextTags(frame, unitKey)    self:ApplyTextPositions(frame, unitKey)    self:ApplyAuraSettings(frame, unitKey)    self:ApplyTagVisibility(frame)    self:ApplyClassBarSettings(frame, unitKey)    self:ApplyUnitCastbarSettings(frame, unitKey)endfunction UnitFrames:ApplyHeaderSettings(header, groupKey)    local settings = self:GetGroupSettings(groupKey)    local layout = self:GetLayoutSettings(groupKey)    local db = self:GetDB()    header:ClearAllPoints()    header:SetPoint(        layout.point or "CENTER",        UIParent,        layout.relativePoint or "CENTER",        tonumber(layout.x) or 0,        tonumber(layout.y) or 0    )    header:SetAttribute("point", settings.point or "TOP")    header:SetAttribute("xOffset", tonumber(settings.xOffset) or 0)    header:SetAttribute("yOffset", tonumber(settings.yOffset) or -6)    header:SetAttribute("unitsPerColumn", math_max(1, tonumber(settings.unitsPerColumn) or 5))    header:SetAttribute("maxColumns", math_max(1, tonumber(settings.maxColumns) or 1))    header:SetAttribute("columnSpacing", tonumber(settings.columnSpacing) or 8)    header:SetAttribute("columnAnchorPoint", settings.columnAnchorPoint or "LEFT")    if groupKey == "party" then        header:SetAttribute("showParty", settings.enabled ~= false)        header:SetAttribute("showPlayer", settings.showPlayer == true)        header:SetAttribute("showSolo", settings.showSolo == true)    elseif groupKey == "raid" then        header:SetAttribute("showRaid", settings.enabled ~= false)        header:SetAttribute("showParty", false)        header:SetAttribute("showSolo", settings.showSolo == true)        header:SetAttribute("groupBy", settings.groupBy or "GROUP")        header:SetAttribute("groupingOrder", settings.groupingOrder or "1,2,3,4,5,6,7,8")    elseif groupKey == "tank" then        header:SetAttribute("showRaid", settings.enabled ~= false)        header:SetAttribute("showParty", false)        header:SetAttribute("showSolo", settings.showSolo == true)        header:SetAttribute("groupFilter", settings.groupFilter or "MAINTANK,MAINASSIST")    end    header:SetScale(Clamp(self:GetDB().scale or 1, 0.6, 1.6))    header:SetAlpha(Clamp(self:GetDB().frameAlpha or 1, 0.15, 1))    header:SetShown(settings.enabled ~= false and db.testMode ~= true)    local childUnitKey = ResolveHeaderChildUnitKey(groupKey)    if childUnitKey and type(header.GetChildren) == "function" then        for _, child in next, { header:GetChildren() } do            if child then                local resolvedUnit = ResolveFrameUnit(child, child.unit)                if resolvedUnit then                    child.unit = resolvedUnit                end                self:ApplySingleFrameSettings(child, childUnitKey)                if type(child.UpdateAllElements) == "function" then                    child:UpdateAllElements("TwichUIHeaderRefresh")                end            end        end    endendfunction UnitFrames:ApplyBossLayout()    if not self.bossAnchor then        return    end    local layout = self:GetLayoutSettings("boss")    local settings = self:GetGroupSettings("boss")    self.bossAnchor:ClearAllPoints()    self.bossAnchor:SetPoint(        layout.point or "RIGHT",        UIParent,        layout.relativePoint or "RIGHT",        tonumber(layout.x) or -300,        tonumber(layout.y) or 0    )    self.bossAnchor:SetScale(Clamp(self:GetDB().scale or 1, 0.6, 1.6))    self.bossAnchor:SetAlpha(Clamp(self:GetDB().frameAlpha or 1, 0.15, 1))    self.bossAnchor:SetShown(settings.enabled ~= false)    local yOffset = tonumber(settings.yOffset) or -8    for index = 1, 5 do        local frame = self.frames["boss" .. index]        if frame then            frame:ClearAllPoints()            if index == 1 then                frame:SetPoint("TOP", self.bossAnchor, "TOP", 0, 0)            else                frame:SetPoint("TOP", self.frames["boss" .. (index - 1)], "BOTTOM", 0, yOffset)            end            frame:SetShown(settings.enabled ~= false)        end    endendfunction UnitFrames:PersistLayoutFromFrame(layoutKey, frame, absX, absY)    local layout = self:GetLayoutSettings(layoutKey)    layout.point = "BOTTOMLEFT"    layout.relativePoint = "BOTTOMLEFT"    layout.x = math.floor((absX or 0) + 0.5)    layout.y = math.floor((absY or 0) + 0.5)    if frame and frame.GetWidth and frame.GetHeight then        local width = frame:GetWidth()        local height = frame:GetHeight()        if width and width > 0 then            local unitSettings = self:GetUnitSettings(layoutKey)            if unitSettings and unitSettings.width ~= nil then                unitSettings.width = math.floor(width + 0.5)            end        end        if height and height > 0 then            local unitSettings = self:GetUnitSettings(layoutKey)            if unitSettings and unitSettings.height ~= nil then                unitSettings.height = math.floor(height + 0.5)            end        end    endendfunction UnitFrames:PersistDetachedAnchor(parentFrame, settings, pointKey, relativePointKey, xKey, yKey, absX, absY)    if not parentFrame or not settings then        return    end    local parentLeft = parentFrame:GetLeft()    local parentBottom = parentFrame:GetBottom()    if not parentLeft or not parentBottom then        return    end    settings[pointKey] = "BOTTOMLEFT"    settings[relativePointKey] = "BOTTOMLEFT"    settings[xKey] = Round((absX or 0) - parentLeft)    settings[yKey] = Round((absY or 0) - parentBottom)end-- Creates a free-floating mover frame identified by layoutKey.-- onMoved(x, y) is called with BOTTOMLEFT screen coordinates on drop.function UnitFrames:AttachMover(layoutKey, label, onMoved)    if self.movers[layoutKey] then        return    end    local mover = CreateFrame("Frame", nil, UIParent, "BackdropTemplate")    mover:SetFrameStrata("HIGH")    mover:SetFrameLevel(250)    mover:SetBackdrop({        bgFile = "Interface\\Buttons\\WHITE8x8",        edgeFile = "Interface\\Buttons\\WHITE8x8",        edgeSize = 1,    })    mover:SetBackdropColor(0.10, 0.72, 0.74, 0.12)    mover:SetBackdropBorderColor(0.10, 0.72, 0.74, 0.85)    mover.label = mover:CreateFontString(nil, "OVERLAY")    mover.label:SetPoint("CENTER", mover, "CENTER", 0, 0)    self:ApplyFontObject(mover.label, 11)    mover.label:SetText(label or BuildFrameName(layoutKey))    mover:SetScript("OnMouseDown", function(selfFrame)        if InCombatLockdown() then return end        selfFrame:StartMoving()        selfFrame.isMoving = true    end)    mover:SetScript("OnMouseUp", function(selfFrame)        if not selfFrame.isMoving then return end        selfFrame:StopMovingOrSizing()        selfFrame.isMoving = false        local x = selfFrame:GetLeft() or 0        local y = selfFrame:GetBottom() or 0        if onMoved then onMoved(x, y) end    end)    mover:EnableMouse(true)    mover:SetMovable(true)    mover:RegisterForDrag("LeftButton")    mover:SetScript("OnDragStart", mover:GetScript("OnMouseDown"))    mover:SetScript("OnDragStop", mover:GetScript("OnMouseUp"))    self.movers[layoutKey] = moverendlocal MAX_AURA_BAR_POOL = 12local function CreateAuraBarFrame(parent)    local bar = CreateFrame("StatusBar", nil, parent, "BackdropTemplate")    bar:SetBackdrop({        bgFile = "Interface\\Buttons\\WHITE8x8",        edgeFile = "Interface\\Buttons\\WHITE8x8",        edgeSize = 1,    })    bar:SetBackdropColor(0.04, 0.05, 0.07, 0.95)    bar:SetBackdropBorderColor(0.16, 0.18, 0.24, 0.85)    bar:SetMinMaxValues(0, 1)    bar:SetValue(1)    local iconTex = bar:CreateTexture(nil, "ARTWORK")    iconTex:SetTexCoord(0.08, 0.92, 0.08, 0.92)    bar.icon = iconTex    local label = bar:CreateFontString(nil, "OVERLAY")    label:SetJustifyH("LEFT")    label:SetWordWrap(false)    bar.label = label    local timeText = bar:CreateFontString(nil, "OVERLAY")    timeText:SetJustifyH("RIGHT")    bar.timeText = timeText    bar:SetScript("OnUpdate", function(self, _)        if not self._duration or self._duration <= 0 then            self:SetValue(1)            if self.timeText then self.timeText:SetText("") end            return        end        local remaining = math_max(0, (self._expiry or 0) - GetTime())        self:SetValue(remaining)        if remaining > 10 then            self.timeText:SetText(string.format("%d", math.floor(remaining + 0.5)))        elseif remaining > 0 then            self.timeText:SetText(string.format("%.1f", remaining))        else            self.timeText:SetText("")        end    end)    bar:Hide()    return barendfunction UnitFrames:EnsureAuraBarsContainer(frame)    if frame.AuraBars then return frame.AuraBars end    local container = CreateFrame("Frame", nil, frame)    container.pool = {}    for i = 1, MAX_AURA_BAR_POOL do        container.pool[i] = CreateAuraBarFrame(container)    end    frame.AuraBars = container    return containerendlocal function CollectAuraData(auraList, unit, auraFilter, maxCount, onlyMine, filterMode)    if not C_UnitAuras or not C_UnitAuras.GetAuraSlots or not IsValidAuraUnit(unit) then        return    end    local playerFilter = auraFilter .. "|PLAYER"    local slots = { C_UnitAuras.GetAuraSlots(unit, auraFilter) }    for index = 2, #slots do        local data = C_UnitAuras.GetAuraDataBySlot(unit, slots[index])        if data then            local resolvedData = {}            for key, value in pairs(data) do                resolvedData[key] = value            end            resolvedData.isPlayerAura = not C_UnitAuras.IsAuraFilteredOutByInstanceID(unit, data.auraInstanceID, playerFilter)            resolvedData.isHarmfulAura = auraFilter:find("HARMFUL") ~= nil            if (not onlyMine or resolvedData.isPlayerAura == true) and AuraMatchesDisplayMode(filterMode, resolvedData) then                auraList[#auraList + 1] = resolvedData                if #auraList >= maxCount then                    break                end            end        end    endendfunction UnitFrames:RefreshAuraBarsForFrame(frame, unitKey)    if not frame.AuraBars then return end    local unit = frame.unit    if not unit then return end    local aura = self:GetAuraConfigFor(unitKey)    local maxBars = math_max(1, math.min(math.floor(tonumber(aura.maxIcons) or 8), MAX_AURA_BAR_POOL))    local barH = Clamp(aura.barHeight or 14, 8, 30)    local spacing = Clamp(aura.spacing or 2, 0, 8)    local filter = aura.filter or "ALL"    local onlyMine = aura.onlyMine == true    local container = frame.AuraBars    local frameWidth = math_max(40, frame:GetWidth())    local texture = GetThemeTexture()    local palette = self:GetPalette(unitKey, unit)    local text = self:GetTextConfigFor(unitKey)    local auraList = {}    if filter == "HELPFUL" then        CollectAuraData(auraList, unit, "HELPFUL", maxBars, onlyMine, filter)    elseif filter == "HARMFUL" or filter == "DISPELLABLE" or filter == "DISPELLABLE_OR_BOSS" then        CollectAuraData(auraList, unit, "HARMFUL", maxBars, onlyMine, filter)    else        CollectAuraData(auraList, unit, "HELPFUL", maxBars, onlyMine, filter)        if #auraList < maxBars then            CollectAuraData(auraList, unit, "HARMFUL", maxBars, onlyMine, filter)        end    end    local shownCount = 0    for i = 1, MAX_AURA_BAR_POOL do        local bar = container.pool[i]        if not bar then break end        local data = (i <= maxBars) and auraList[i] or nil        if data then            bar:SetWidth(frameWidth)            bar:SetHeight(barH)            bar:ClearAllPoints()            if i == 1 then                bar:SetPoint("TOP", container, "TOP", 0, 0)            else                bar:SetPoint("TOP", container.pool[i - 1], "BOTTOM", 0, -spacing)            end            bar:SetStatusBarTexture(texture)            local duration = tonumber(data.duration) or 0            local expiry = tonumber(data.expirationTime) or 0            if duration > 0 then                bar:SetMinMaxValues(0, duration)                bar._duration = duration                bar._expiry = expiry                bar:SetStatusBarColor(palette.cast[1], palette.cast[2], palette.cast[3], 0.85)            else                bar:SetMinMaxValues(0, 1)                bar:SetValue(1)                bar._duration = 0                bar._expiry = 0                bar:SetStatusBarColor(palette.health[1], palette.health[2], palette.health[3], 0.7)            end            local iconSize = barH - 2            if bar.icon then                bar.icon:SetTexture(data.icon)                bar.icon:SetSize(iconSize, iconSize)                bar.icon:ClearAllPoints()                bar.icon:SetPoint("LEFT", bar, "LEFT", 1, 0)            end            if bar.label then                self:ApplyFontObject(bar.label, math_max(7, barH - 4), text.fontName, text)                bar.label:ClearAllPoints()                bar.label:SetPoint("LEFT", bar, "LEFT", iconSize + 4, 0)                bar.label:SetPoint("RIGHT", bar, "RIGHT", -32, 0)                bar.label:SetText(data.name or "")            end            if bar.timeText then                self:ApplyFontObject(bar.timeText, math_max(7, barH - 4), text.fontName, text)                bar.timeText:ClearAllPoints()                bar.timeText:SetPoint("RIGHT", bar, "RIGHT", -3, 0)            end            bar:Show()            shownCount = shownCount + 1        else            bar._duration = nil            bar._expiry = nil            bar:Hide()        end    end    container:SetWidth(frameWidth)    container:SetHeight(math_max(1, shownCount * barH + math_max(0, shownCount - 1) * spacing))endfunction UnitFrames:ApplyClassBarSettings(frame, unitKey)    if unitKey ~= "player" or not frame.ClassPower or not frame.ClassPower.container then        return    end    local db = self:GetDB()    local cfg = db.classBar or {}    local enabled = cfg.enabled ~= false    local width = Clamp(cfg.width or GetUsableSize(frame:GetWidth(), 260), 40, 600)    local height = Clamp(cfg.height or 10, 4, 40)    local spacing = Clamp(cfg.spacing or 2, 0, 10)    local textureName = (db.texture and db.texture ~= "") and db.texture or nil    local texture = textureName and GetLSMTexture(textureName) or GetThemeTexture()    local container = frame.ClassPower.container    container:ClearAllPoints()    container:SetPoint(        cfg.point or "TOPLEFT",        frame,        cfg.relativePoint or "BOTTOMLEFT",        tonumber(cfg.xOffset) or 0,        tonumber(cfg.yOffset) or -2    )    container:SetSize(width, height)    local visibleBars = #frame.ClassPower    local barWidth = math_max(4, (width - (spacing * math_max(0, visibleBars - 1))) / math_max(1, visibleBars))    for index = 1, #frame.ClassPower do        local bar = frame.ClassPower[index]        bar:ClearAllPoints()        bar:SetSize(barWidth, height)        if index == 1 then            bar:SetPoint("LEFT", container, "LEFT", 0, 0)        else            bar:SetPoint("LEFT", frame.ClassPower[index - 1], "RIGHT", spacing, 0)        end        bar:SetStatusBarTexture(texture)        bar:SetBackdropColor(0.05, 0.06, 0.08, 0.9)        bar:SetBackdropBorderColor(0.24, 0.26, 0.32, 0.9)        if not enabled then            bar:Hide()        end    end    container:SetShown(enabled)    self:ApplyClassBarColors(frame)    if frame.ClassPower.ForceUpdate then        frame.ClassPower:ForceUpdate()    endendfunction UnitFrames:ApplyUnitCastbarSettings(frame, unitKey)    if not frame.Castbar then return end    local db = self:GetDB()    local castbars = db.castbars or {}    local scope = ResolveCastbarScopeByUnitKey(unitKey)    local cfg = castbars[scope] or {}    local enabled = cfg.enabled ~= false    local detached = cfg.detached == true    local barH = Clamp(cfg.height or 12, 4, 40)    local palette = self:GetPalette(unitKey, ResolveFrameUnit(frame, frame.unit))    local text = self:GetTextConfigFor(unitKey)    frame.Castbar:SetHeight(barH)    frame.Castbar.smoothing = self:GetCastbarSmoothingMethod()    frame.Castbar:ClearAllPoints()    if detached then        frame.Castbar:SetWidth(Clamp(cfg.width or GetUsableSize(frame:GetWidth(), 220), 40, 600))        frame.Castbar:SetPoint(            cfg.point or "TOPLEFT",            frame,            cfg.relativePoint or "BOTTOMLEFT",            tonumber(cfg.xOffset) or 0,            tonumber(cfg.yOffset) or -2        )    else        frame.Castbar:SetPoint("TOPLEFT", frame, "BOTTOMLEFT", 0, -(cfg.yOffset or 2))        frame.Castbar:SetPoint("TOPRIGHT", frame, "BOTTOMRIGHT", 0, -(cfg.yOffset or 2))    end    local texture = (db.texture and db.texture ~= "") and GetLSMTexture(db.texture) or GetThemeTexture()    frame.Castbar:SetStatusBarTexture(texture)    if cfg.useCustomColor == true and type(cfg.color) == "table" then        local c = cfg.color        frame.Castbar:SetStatusBarColor(c[1] or 1, c[2] or 1, c[3] or 1, c[4] or 1)    else        frame.Castbar:SetStatusBarColor(palette.cast[1], palette.cast[2], palette.cast[3], 1)    end    frame.Castbar:SetBackdropColor(        palette.background[1], palette.background[2], palette.background[3], 0.9)    frame.Castbar:SetBackdropBorderColor(        palette.border[1], palette.border[2], palette.border[3], 0.9)    if frame.Castbar.Text then        self:ApplyFontObject(frame.Castbar.Text, Clamp(cfg.fontSize or 9, 6, 20), text.fontName, text)        frame.Castbar.Text:SetShown(cfg.showText ~= false)    end    if frame.Castbar.Time then        self:ApplyFontObject(frame.Castbar.Time, Clamp(cfg.timeFontSize or 9, 6, 20), text.fontName, text)        frame.Castbar.Time:SetShown(cfg.showTimeText ~= false)    end    if frame.Castbar.Icon then        local iconSize = math_max(4, barH - 2)        frame.Castbar.Icon:SetSize(iconSize, iconSize)        frame.Castbar.Icon:SetShown(cfg.showIcon ~= false)    end    if not enabled then        frame.Castbar:Hide()    elseif frame.Castbar.ForceUpdate then        frame.Castbar:ForceUpdate()    endendfunction UnitFrames:UpdateMovers()    local db = self:GetDB()    local showMovers = db.lockFrames ~= true    local function PlaceMover(mover, layout, width, height, enabled)        if not mover then return end        mover:SetSize(math_max(20, width), math_max(10, height))        mover:ClearAllPoints()        mover:SetPoint(            layout.point or "BOTTOMLEFT",            UIParent,            layout.relativePoint or "BOTTOMLEFT",            tonumber(layout.x) or 0,            tonumber(layout.y) or 0        )        mover:SetShown(showMovers and enabled ~= false)    end    local function PlaceAnchoredMover(mover, anchorFrame, point, relativePoint, xOffset, yOffset, width, height, enabled)        if not mover then return end        if not anchorFrame then            mover:Hide()            return        end        mover:SetSize(math_max(20, width), math_max(10, height))        mover:ClearAllPoints()        mover:SetPoint(            point or "BOTTOMLEFT",            anchorFrame,            relativePoint or "BOTTOMLEFT",            tonumber(xOffset) or 0,            tonumber(yOffset) or 0        )        mover:SetShown(showMovers and enabled ~= false)    end    local function EnsureLayoutMover(layoutKey, label)        if not self.movers[layoutKey] then            self:AttachMover(layoutKey, label, function(x, y)                local layout = UnitFrames:GetLayoutSettings(layoutKey)                layout.point = "BOTTOMLEFT"                layout.relativePoint = "BOTTOMLEFT"                layout.x = Round(x)                layout.y = Round(y)                UnitFrames:RefreshAllFrames()            end)        end        return self.movers[layoutKey]    end    local function EnsurePowerMover(unitKey, label)        local moverKey = unitKey .. "_power"        if not self.movers[moverKey] then            self:AttachMover(moverKey, label, function(x, y)                local parentFrame = UnitFrames.frames[unitKey]                if not parentFrame then                    return                end                local settings = UnitFrames:GetUnitSettings(unitKey)                UnitFrames:PersistDetachedAnchor(                    parentFrame,                    settings,                    "powerPoint",                    "powerRelativePoint",                    "powerOffsetX",                    "powerOffsetY",                    x,                    y                )                UnitFrames:RefreshAllFrames()            end)        end        return self.movers[moverKey]    end    local function EnsureClassBarMover()        local moverKey = "player_classbar"        if not self.movers[moverKey] then            self:AttachMover(moverKey, "Player Class Bar", function(x, y)                local parentFrame = UnitFrames.frames.player                if not parentFrame then                    return                end                local dbRef = UnitFrames:GetDB()                dbRef.classBar = dbRef.classBar or {}                local classBar = dbRef.classBar                UnitFrames:PersistDetachedAnchor(                    parentFrame,                    classBar,                    "point",                    "relativePoint",                    "xOffset",                    "yOffset",                    x,                    y                )                UnitFrames:RefreshAllFrames()            end)        end        return self.movers[moverKey]    end    local function GetDetachedCastbarAnchorFrame(scope)        if scope == "target" then            return self.frames.target or (db.testMode == true and self.previewFrames.target) or nil        end        if scope == "boss" then            return self.frames.boss1 or (db.testMode == true and self.previewFrames.boss1) or nil        end        if scope == "party" then            return GetFirstHeaderChild(self.headers.party)                or (db.testMode == true and self.previewFrames.party and self.previewFrames.party.rows and self.previewFrames.party.rows[1])                or nil        end        if scope == "raid" then            return GetFirstHeaderChild(self.headers.raid)                or (db.testMode == true and self.previewFrames.raid and self.previewFrames.raid.rows and self.previewFrames.raid.rows[1])                or nil        end        return nil    end    local function EnsureDetachedCastbarMover(scope, label)        local moverKey = scope .. "_castbar"        if not self.movers[moverKey] then            self:AttachMover(moverKey, label, function(x, y)                local parentFrame = GetDetachedCastbarAnchorFrame(scope)                if not parentFrame then                    return                end                local dbRef = UnitFrames:GetDB()                dbRef.castbars = dbRef.castbars or {}                dbRef.castbars[scope] = dbRef.castbars[scope] or {}                UnitFrames:PersistDetachedAnchor(                    parentFrame,                    dbRef.castbars[scope],                    "point",                    "relativePoint",                    "xOffset",                    "yOffset",                    x,                    y                )                UnitFrames:RefreshAllFrames()            end)        end        return self.movers[moverKey]    end    local singleEntries = {        { key = "player",       label = "Player" },        { key = "target",       label = "Target" },        { key = "targettarget", label = "Target of Target" },        { key = "focus",        label = "Focus" },        { key = "pet",          label = "Pet" },    }    for _, entry in ipairs(singleEntries) do        local key = entry.key        EnsureLayoutMover(key, entry.label)        local s = self:GetUnitSettings(key)        PlaceMover(self.movers[key], self:GetLayoutSettings(key),            Clamp(s.width or 220, 80, 600),            Clamp(s.height or 42, 16, 180),            s.enabled ~= false)        PlaceAnchoredMover(            EnsurePowerMover(key, entry.label .. " Power Bar"),            self.frames[key],            s.powerPoint or "TOPLEFT",            s.powerRelativePoint or "BOTTOMLEFT",            s.powerOffsetX,            s.powerOffsetY,            Clamp(s.powerWidth or s.width or 220, 40, 600),            Clamp(s.powerHeight or 10, 4, 32),            s.enabled ~= false and s.showPower ~= false and s.powerDetached == true        )    end    EnsureLayoutMover("castbar", "Cast Bar")    do        local cs = db.castbar or {}        PlaceMover(self.movers["castbar"], self:GetLayoutSettings("castbar"),            Clamp(cs.width or 260, 120, 600),            Clamp(cs.height or 20, 10, 60),            cs.enabled ~= false)    end    do        local classCfg = db.classBar or {}        PlaceAnchoredMover(            EnsureClassBarMover(),            self.frames.player,            classCfg.point or "TOPLEFT",            classCfg.relativePoint or "BOTTOMLEFT",            classCfg.xOffset,            classCfg.yOffset,            Clamp(classCfg.width or 260, 40, 600),            Clamp(classCfg.height or 10, 4, 40),            classCfg.enabled ~= false and self.frames.player ~= nil                and self:GetUnitSettings("player").enabled ~= false        )    end    local groupEntries = {        { key = "party", label = "Party Frames" },        { key = "raid",  label = "Raid Frames" },        { key = "tank",  label = "Tank Frames" },        { key = "boss",  label = "Boss Frames" },    }    for _, entry in ipairs(groupEntries) do        local key = entry.key        EnsureLayoutMover(key, entry.label)        local gs = self:GetGroupSettings(key)        local layout = self:GetLayoutSettings(key)        local mw, mh = 180, 100        if key == "party" then            local w = Clamp(gs.width or 180, 80, 500)            local h = Clamp(gs.height or 36, 14, 120)            mw = w            mh = (h + math_abs(tonumber(gs.yOffset) or 6)) * 5        elseif key == "raid" then            local w = Clamp(gs.width or 120, 70, 300)            local h = Clamp(gs.height or 30, 14, 80)            local cols = math_max(1, tonumber(gs.maxColumns) or 4)            local colSpacing = tonumber(gs.columnSpacing) or 6            mw = (w + colSpacing) * cols            mh = (h + math_abs(tonumber(gs.yOffset) or 6)) * math_max(1, tonumber(gs.unitsPerColumn) or 5)        elseif key == "tank" then            local w = Clamp(gs.width or 180, 80, 400)            local h = Clamp(gs.height or 32, 14, 80)            mw = w            mh = (h + math_abs(tonumber(gs.yOffset) or 6)) * 2        elseif key == "boss" then            local bs = self:GetUnitSettings("boss")            local w = Clamp(bs.width or 220, 120, 500)            local h = Clamp(bs.height or 36, 16, 120)            mw = w            mh = (h + math_abs(tonumber(gs.yOffset) or 8)) * 5        end        PlaceMover(self.movers[key], layout, mw, mh, gs.enabled ~= false)    end    local detachedCastbarEntries = {        { scope = "target", label = "Target Cast Bar" },        { scope = "boss", label = "Boss Cast Bar" },        { scope = "party", label = "Party Cast Bar" },        { scope = "raid", label = "Raid Cast Bar" },    }    for _, entry in ipairs(detachedCastbarEntries) do        local scope = entry.scope        db.castbars = db.castbars or {}        db.castbars[scope] = db.castbars[scope] or {}        local cfg = db.castbars[scope]        local anchorFrame = GetDetachedCastbarAnchorFrame(scope)        local fallbackWidth = anchorFrame and anchorFrame:GetWidth() or 220        local scopeEnabled = true        if scope == "target" then            scopeEnabled = self:GetUnitSettings("target").enabled ~= false        elseif scope == "boss" then            scopeEnabled = self:GetGroupSettings("boss").enabled ~= false                and self:GetUnitSettings("boss").enabled ~= false        elseif scope == "party" or scope == "raid" then            scopeEnabled = self:GetGroupSettings(scope).enabled ~= false        end        PlaceAnchoredMover(            EnsureDetachedCastbarMover(scope, entry.label),            anchorFrame,            cfg.point or "TOPLEFT",            cfg.relativePoint or "BOTTOMLEFT",            cfg.xOffset,            cfg.yOffset,            Clamp(cfg.width or fallbackWidth, 40, 600),            Clamp(cfg.height or 12, 4, 40),            cfg.enabled ~= false and cfg.detached == true and scopeEnabled        )    end    if not showMovers then        for _, mover in pairs(self.movers) do            if mover then mover:Hide() end        end    endendfunction UnitFrames:RegisterLayoutFrame(layoutKey, frame)    local setupWizard = T:GetModule("SetupWizard", true)    if not setupWizard or not frame then        return    end    setupWizard:RegisterLayoutFrame("UF_" .. layoutKey, frame, function(absX, absY, absW, absH)        local layout = UnitFrames:GetLayoutSettings(layoutKey)        layout.point = "BOTTOMLEFT"        layout.relativePoint = "BOTTOMLEFT"        layout.x = math.floor((absX or 0) + 0.5)        layout.y = math.floor((absY or 0) + 0.5)        if layoutKey == "party" or layoutKey == "raid" or layoutKey == "tank" or layoutKey == "boss" then            return        end        local unitSettings = UnitFrames:GetUnitSettings(layoutKey)        if absW and absW > 20 then            unitSettings.width = math.floor(absW + 0.5)        end        if absH and absH > 12 then            unitSettings.height = math.floor(absH + 0.5)        end    end)endfunction UnitFrames:CreatePreviewFrame(parent, width, height, label)    local frame = CreateFrame("Frame", nil, parent, "BackdropTemplate")    frame:SetSize(width, height)    frame:SetBackdrop({        bgFile = "Interface\\Buttons\\WHITE8x8",        edgeFile = "Interface\\Buttons\\WHITE8x8",        edgeSize = 1,    })    frame:SetBackdropColor(0.05, 0.06, 0.08, 0.9)    frame:SetBackdropBorderColor(0.24, 0.26, 0.32, 0.9)    local hp = CreateFrame("StatusBar", nil, frame)    hp:SetPoint("TOPLEFT", frame, "TOPLEFT", 1, -1)    hp:SetPoint("TOPRIGHT", frame, "TOPRIGHT", -1, -1)    hp:SetHeight(math_max(8, height - 12))    hp:SetStatusBarTexture(GetThemeTexture())    hp:SetStatusBarColor(0.34, 0.84, 0.54, 1)    hp:SetMinMaxValues(0, 100)    hp:SetValue(70)    local pw = CreateFrame("StatusBar", nil, frame)    pw:SetPoint("TOPLEFT", hp, "BOTTOMLEFT", 0, -1)    pw:SetPoint("TOPRIGHT", hp, "BOTTOMRIGHT", 0, -1)    pw:SetHeight(8)    pw:SetStatusBarTexture(GetThemeTexture())    pw:SetStatusBarColor(0.10, 0.72, 0.74, 1)    pw:SetMinMaxValues(0, 100)    pw:SetValue(45)    -- Name label: on health bar so it renders above the bar texture.    local nameText = hp:CreateFontString(nil, "OVERLAY")    nameText:SetPoint("LEFT", hp, "LEFT", 4, 0)    nameText:SetPoint("RIGHT", hp, "RIGHT", -56, 0)    nameText:SetJustifyH("LEFT")    self:ApplyFontObject(nameText, 10)    nameText:SetText(label)    -- Health value: right side of health bar.    local healthText = hp:CreateFontString(nil, "OVERLAY")    healthText:SetPoint("RIGHT", hp, "RIGHT", -4, 0)    healthText:SetJustifyH("RIGHT")    self:ApplyFontObject(healthText, 9)    healthText:SetText("100%")    local castbar = CreateFrame("StatusBar", nil, frame, "BackdropTemplate")    castbar:SetMinMaxValues(0, 100)    castbar:SetValue(64)    castbar:SetBackdrop({        bgFile = "Interface\\Buttons\\WHITE8x8",        edgeFile = "Interface\\Buttons\\WHITE8x8",        edgeSize = 1,    })    castbar:SetBackdropColor(0.05, 0.06, 0.08, 0.9)    castbar:SetBackdropBorderColor(0.24, 0.26, 0.32, 0.9)    local cbText = castbar:CreateFontString(nil, "OVERLAY")    cbText:SetPoint("LEFT", castbar, "LEFT", 4, 0)    cbText:SetPoint("RIGHT", castbar, "RIGHT", -30, 0)    cbText:SetJustifyH("LEFT")    castbar.Text = cbText    local cbTime = castbar:CreateFontString(nil, "OVERLAY")    cbTime:SetPoint("RIGHT", castbar, "RIGHT", -3, 0)    cbTime:SetJustifyH("RIGHT")    castbar.Time = cbTime    local cbIcon = castbar:CreateTexture(nil, "ARTWORK")    cbIcon:SetSize(12, 12)    cbIcon:SetPoint("RIGHT", castbar, "LEFT", -2, 0)    cbIcon:SetTexCoord(0.08, 0.92, 0.08, 0.92)    castbar.Icon = cbIcon    frame.HealthBar = hp    frame.PowerBar = pw    frame.Label = nameText    frame.HealthText = healthText    frame.Castbar = castbar    return frameendlocal HEALTH_FORMAT_MOCK = {    percent = "100%",    current = "125,680",    currentPercent = "125k  100%",    missing = "0",}local POWER_FORMAT_MOCK = {    percent = "100%",    current = "12,450",    currentPercent = "12k  100%",    missing = "0",}local PREVIEW_CASTBAR_MOCK = {    target = { name = "Chaos Bolt", time = "1.6", icon = 136197 },    boss = { name = "Molten Slam", time = "2.3", icon = 135826 },    party = { name = "Regrowth", time = "1.4", icon = 136085 },    raid = { name = "Chain Heal", time = "1.8", icon = 136042 },}function UnitFrames:UpdatePreviewCastbar(frame, unitKey)    if not frame or not frame.Castbar or not unitKey or unitKey == "player" then        if frame and frame.Castbar then            frame.Castbar:Hide()        end        return    end    local scope = ResolveCastbarScopeByUnitKey(unitKey)    local cfg = ((self:GetDB().castbars or {})[scope]) or {}    if cfg.enabled == false then        frame.Castbar:Hide()        return    end    self:ApplyUnitCastbarSettings(frame, unitKey)    local mock = PREVIEW_CASTBAR_MOCK[scope] or PREVIEW_CASTBAR_MOCK.target    frame.Castbar:SetMinMaxValues(0, 100)    frame.Castbar:SetValue(64)    if frame.Castbar.Icon then        frame.Castbar.Icon:SetTexture(mock.icon)    end    if frame.Castbar.Text then        frame.Castbar.Text:SetText(mock.name)    end    if frame.Castbar.Time then        frame.Castbar.Time:SetText(mock.time)    end    frame.Castbar:Show()endfunction UnitFrames:UpdatePreviewFrame(frame, width, height, label, unitKey)    if not frame then        return    end    frame:SetSize(width, height)    if frame.HealthBar then        frame.HealthBar:SetHeight(math_max(8, height - 12))        frame.HealthBar:SetStatusBarTexture(GetThemeTexture())    end    if frame.PowerBar then        frame.PowerBar:SetStatusBarTexture(GetThemeTexture())    end    if frame.Label then        frame.Label:SetText(label or "Preview")    end    -- Update mock text values based on configured format.    if unitKey then        local textCfg = self:GetTextConfigFor(unitKey)        if frame.HealthText then            frame.HealthText:SetText(HEALTH_FORMAT_MOCK[textCfg.healthFormat] or "100%")            self:ApplyFontObject(frame.HealthText, Clamp(textCfg.healthFontSize or 9, 6, 28), textCfg.fontName, textCfg)        end        if frame.Label then            self:ApplyFontObject(frame.Label, Clamp(textCfg.nameFontSize or 10, 6, 28), textCfg.fontName, textCfg)        end        self:UpdatePreviewCastbar(frame, unitKey)    elseif frame.Castbar then        frame.Castbar:Hide()    endendfunction UnitFrames:BuildOrRefreshSinglePreviews()    local preview = self.previewFrames    local db = self:GetDB()    for _, entry in ipairs(PREVIEW_SINGLE_UNITS) do        local settings = self:GetUnitSettings(entry.key)        local layout = self:GetLayoutSettings(entry.key)        local width = Clamp(settings.width or 220, 80, 600)        local height = Clamp(settings.height or 42, 16, 180)        if not preview[entry.key] then            preview[entry.key] = self:CreatePreviewFrame(UIParent, width, height, entry.label)        end        self:UpdatePreviewFrame(preview[entry.key], width, height, entry.label, entry.key)        local frame = preview[entry.key]        frame:ClearAllPoints()        frame:SetPoint(            layout.point or "BOTTOM",            UIParent,            layout.relativePoint or "BOTTOM",            tonumber(layout.x) or 0,            tonumber(layout.y) or 0        )        frame:SetScale(Clamp(db.scale or 1, 0.6, 1.6))        frame:SetAlpha(Clamp(db.frameAlpha or 1, 0.15, 1))    end    if not preview.castbar then        preview.castbar = CreateFrame("StatusBar", nil, UIParent, "BackdropTemplate")        preview.castbar:SetBackdrop({            bgFile = "Interface\\Buttons\\WHITE8x8",            edgeFile = "Interface\\Buttons\\WHITE8x8",            edgeSize = 1,        })        preview.castbar.bg = preview.castbar:CreateTexture(nil, "BACKGROUND")        preview.castbar.bg:SetAllPoints(preview.castbar)        preview.castbar.bg:SetColorTexture(0.05, 0.06, 0.08, 0.9)        preview.castbar.icon = preview.castbar:CreateTexture(nil, "ARTWORK")        preview.castbar.icon:SetTexCoord(0.08, 0.92, 0.08, 0.92)        preview.castbar.icon:SetPoint("RIGHT", preview.castbar, "LEFT", -6, 0)        preview.castbar.icon:SetSize(20, 20)        preview.castbar.icon:SetTexture(136243)        preview.castbar.spellText = preview.castbar:CreateFontString(nil, "OVERLAY")        preview.castbar.spellText:SetPoint("LEFT", preview.castbar, "LEFT", 6, 0)        self:ApplyFontObject(preview.castbar.spellText, 11)        preview.castbar.timeText = preview.castbar:CreateFontString(nil, "OVERLAY")        preview.castbar.timeText:SetPoint("RIGHT", preview.castbar, "RIGHT", -6, 0)        self:ApplyFontObject(preview.castbar.timeText, 10)    end    do        local castSettings = db.castbar or {}        local layout = self:GetLayoutSettings("castbar")        local palette = self:GetPalette("singles")        local text = self:GetTextConfigFor("player")        local castPreview = preview.castbar        castPreview:ClearAllPoints()        castPreview:SetPoint(            layout.point or "BOTTOM",            UIParent,            layout.relativePoint or "BOTTOM",            tonumber(layout.x) or -260,            tonumber(layout.y) or 220        )        castPreview:SetSize(Clamp(castSettings.width or 260, 120, 600), Clamp(castSettings.height or 20, 10, 60))        castPreview:SetStatusBarTexture(GetThemeTexture())        if castSettings.useCustomColor == true and type(castSettings.color) == "table" then            castPreview:SetStatusBarColor(castSettings.color[1] or 1, castSettings.color[2] or 1, castSettings.color[3] or 1, castSettings.color[4] or 1)        else            castPreview:SetStatusBarColor(palette.cast[1], palette.cast[2], palette.cast[3], 1)        end        castPreview:SetMinMaxValues(0, 100)        castPreview:SetValue(64)        castPreview.spellText:SetText("Shadow Bolt")        castPreview.timeText:SetText("1.4")        castPreview.spellText:SetShown(castSettings.showSpellText ~= false)        castPreview.timeText:SetShown(castSettings.showTimeText ~= false)        self:ApplyFontObject(castPreview.spellText, Clamp(castSettings.spellFontSize or 11, 6, 24), text.fontName, text)        self:ApplyFontObject(castPreview.timeText, Clamp(castSettings.timeFontSize or 10, 6, 24), text.fontName, text)        if castPreview.icon then            local iconSize = Clamp(castSettings.iconSize or castSettings.height or 20, 12, 50)            castPreview.icon:SetSize(iconSize, iconSize)            castPreview.icon:SetShown(castSettings.showIcon ~= false)        end        castPreview:SetScale(Clamp(db.scale or 1, 0.6, 1.6))        castPreview:SetAlpha(Clamp(db.frameAlpha or 1, 0.15, 1))    end    if not preview.bossAnchor then        preview.bossAnchor = CreateFrame("Frame", nil, UIParent)    end    do        local bossLayout = self:GetLayoutSettings("boss")        local bossGroup = self:GetGroupSettings("boss")        local bossUnit = self:GetUnitSettings("boss")        local width = Clamp(bossUnit.width or 220, 120, 500)        local height = Clamp(bossUnit.height or 36, 16, 120)        local yOffset = tonumber(bossGroup.yOffset) or -8        preview.bossAnchor:ClearAllPoints()        preview.bossAnchor:SetPoint(            bossLayout.point or "RIGHT",            UIParent,            bossLayout.relativePoint or "RIGHT",            tonumber(bossLayout.x) or -60,            tonumber(bossLayout.y) or 520        )        preview.bossAnchor:SetSize(width, (height + math.abs(yOffset)) * 5)        for index = 1, 5 do            local key = "bossPreview" .. index            if not preview[key] then                preview[key] = self:CreatePreviewFrame(preview.bossAnchor, width, height, "Boss " .. index)            end            self:UpdatePreviewFrame(preview[key], width, height, "Boss " .. index, "boss")            preview[key]:ClearAllPoints()            if index == 1 then                preview[key]:SetPoint("TOP", preview.bossAnchor, "TOP", 0, 0)            else                preview[key]:SetPoint("TOP", preview["bossPreview" .. (index - 1)], "BOTTOM", 0, yOffset)            end            preview[key]:SetScale(Clamp(db.scale or 1, 0.6, 1.6))            preview[key]:SetAlpha(Clamp(db.frameAlpha or 1, 0.15, 1))        end    endendfunction UnitFrames:BuildPreviewGroups()    local preview = self.previewFrames    local function EnsureContainer(key)        if not preview[key] then            preview[key] = CreateFrame("Frame", nil, UIParent)            preview[key].rows = {}        end        return preview[key]    end    local function PositionContainer(container, layout)        container:ClearAllPoints()        container:SetPoint(            layout.point or "CENTER",            UIParent,            layout.relativePoint or "CENTER",            tonumber(layout.x) or 0,            tonumber(layout.y) or 0        )    end    local party = EnsureContainer("party")    do        local settings = self:GetGroupSettings("party")        local layout = self:GetLayoutSettings("party")        local width = Clamp(settings.width or 180, 80, 500)        local height = Clamp(settings.height or 36, 14, 120)        local yOffset = tonumber(settings.yOffset) or -6        PositionContainer(party, layout)        party:SetSize(width, (height + math_abs(yOffset)) * 5)        for index = 1, 5 do            if not party.rows[index] then                party.rows[index] = self:CreatePreviewFrame(party, width, height, "Party " .. index)            end            self:UpdatePreviewFrame(party.rows[index], width, height, "Party " .. index, "partyMember")            local row = party.rows[index]            row:ClearAllPoints()            if index == 1 then                row:SetPoint("TOP", party, "TOP", 0, 0)            else                row:SetPoint("TOP", party.rows[index - 1], "BOTTOM", 0, yOffset)            end            row:SetShown(true)        end    end    local raid = EnsureContainer("raid")    do        local settings = self:GetGroupSettings("raid")        local layout = self:GetLayoutSettings("raid")        local width = Clamp(settings.width or 120, 70, 300)        local height = Clamp(settings.height or 30, 14, 80)        local yOffset = tonumber(settings.yOffset) or -6        local colSpacing = tonumber(settings.columnSpacing) or 6        local unitsPerColumn = math_max(1, tonumber(settings.unitsPerColumn) or 5)        local maxColumns = math_max(1, tonumber(settings.maxColumns) or 4)        PositionContainer(raid, layout)        raid:SetSize((width + colSpacing) * maxColumns, (height + math_abs(yOffset)) * unitsPerColumn)        for index = 1, 20 do            if not raid.rows[index] then                raid.rows[index] = self:CreatePreviewFrame(raid, width, height, "Raid " .. index)            end            self:UpdatePreviewFrame(raid.rows[index], width, height, "Raid " .. index, "raidMember")            local row = raid.rows[index]            local column = math.floor((index - 1) / unitsPerColumn)            local rowIndex = (index - 1) % unitsPerColumn            row:ClearAllPoints()            row:SetPoint("TOPLEFT", raid, "TOPLEFT", column * (width + colSpacing), -(rowIndex * (height + math_abs(yOffset))))            row:SetShown(column < maxColumns)    power.PostUpdate = function(powerBar, unit, cur, max)        UnitFrames:ApplySmoothBarValue(powerBar, cur, max)        UnitFrames:ApplyPowerBarColor(powerBar, frame, unitKey, unit, cur, max, "PowerPostUpdate")    end    frame.Power = power        local settings = self:GetGroupSettings("tank")        local layout = self:GetLayoutSettings("tank")        local width = Clamp(settings.width or 180, 80, 400)        local height = Clamp(settings.height or 32, 14, 80)        local yOffset = tonumber(settings.yOffset) or -6        PositionContainer(tank, layout)        tank:SetSize(width, (height + math_abs(yOffset)) * 2)        for index = 1, 2 do            if not tank.rows[index] then                tank.rows[index] = self:CreatePreviewFrame(tank, width, height, "Tank " .. index)            end            self:UpdatePreviewFrame(tank.rows[index], width, height, "Tank " .. index, "tankMember")            local row = tank.rows[index]            row:ClearAllPoints()            if index == 1 then                row:SetPoint("TOP", tank, "TOP", 0, 0)            else                row:SetPoint("TOP", tank.rows[index - 1], "BOTTOM", 0, yOffset)            end            row:SetShown(true)        end    endendfunction UnitFrames:RefreshPreviewVisibility()    self:BuildPreviewGroups()    self:BuildOrRefreshSinglePreviews()    local db = self:GetDB()    local showPreview = db.testMode == true    for key, container in pairs(self.previewFrames) do        if container then            local shouldShow = showPreview            if key == "castbar" then                shouldShow = shouldShow and ((db.castbar and db.castbar.enabled ~= false) ~= false)            elseif key:match("^bossPreview") then                shouldShow = shouldShow and (self:GetGroupSettings("boss").enabled ~= false)            elseif key == "bossAnchor" then                shouldShow = shouldShow and (self:GetGroupSettings("boss").enabled ~= false)            elseif key == "player" or key == "target" or key == "targettarget" or key == "focus" or key == "pet" then                shouldShow = shouldShow and (self:GetUnitSettings(key).enabled ~= false)            elseif key == "party" or key == "raid" or key == "tank" then                shouldShow = shouldShow and (self:GetGroupSettings(key).enabled ~= false)            end            container:SetShown(shouldShow)        end    endendfunction UnitFrames:ApplyTestModeToSingles()    -- Test mode visuals are handled via dedicated preview frames so live oUF    -- visibility logic cannot hide or taint inactive units.endfunction UnitFrames:RefreshAllFrames()    if InCombatLockdown() then        self._queuedRefresh = true        return    end    for unitKey, frame in pairs(self.frames) do        if unitKey ~= "castbar" then            self:ApplySingleFrameSettings(frame, unitKey)        end    end    for groupKey, header in pairs(self.headers) do        self:ApplyHeaderSettings(header, groupKey)    end    self:ApplyBossLayout()    self:RefreshCastbarLayout()    self:RefreshCastbarStyle()    self:RefreshPreviewVisibility()    self:ApplyTestModeToSingles()    self:UpdateMovers()endfunction UnitFrames:OnThemeChanged()    self:RefreshAllFrames()endfunction UnitFrames:OnConfigRestored()    self:RefreshAllFrames()endfunction UnitFrames:StyleFrame(frame)    local unit = frame.unit or "unit"    local unitKey = unit    local parent = frame:GetParent()    local parentName = parent and parent:GetName() or ""    -- Use parent frame name (not pointer) to avoid race condition in SpawnHeaders.    if parentName == "TwichUIUF_PartyHeader" then        unitKey = "partyMember"        frame.isHeaderChild = true    elseif parentName == "TwichUIUF_RaidHeader" then        unitKey = "raidMember"        frame.isHeaderChild = true    elseif parentName == "TwichUIUF_TankHeader" then        unitKey = "tankMember"        frame.isHeaderChild = true    elseif unit:match("^boss") then        unitKey = "boss"    end    frame:SetAttribute("useparent-unit", true)    frame:RegisterForClicks("AnyUp")    local health = CreateFrame("StatusBar", nil, frame)    health:SetPoint("TOPLEFT", frame, "TOPLEFT", 0, 0)    health:SetPoint("TOPRIGHT", frame, "TOPRIGHT", 0, 0)    health:SetHeight(30)    health.colorClass = false    health.colorDisconnected = false    health.colorReaction = false    health.colorTapping = false    health.frequentUpdates = true    health.PostUpdate = function(healthBar, unit, cur, max)        UnitFrames:ApplySmoothBarValue(healthBar, cur, max)        local palette = UnitFrames:GetPalette(unitKey, ResolveFrameUnit(frame, unit))        healthBar:SetStatusBarColor(palette.health[1], palette.health[2], palette.health[3], 1)    end    frame.Health = health    local power = CreateFrame("StatusBar", nil, frame)    power:SetPoint("TOPLEFT", health, "BOTTOMLEFT", 0, -1)    power:SetPoint("TOPRIGHT", health, "BOTTOMRIGHT", 0, -1)    power:SetHeight(10)    power.colorClass = false    power.colorDisconnected = false    power.colorPower = false    power.colorReaction = false    power.colorTapping = false    power.frequentUpdates = true    power.PostUpdate = function(powerBar, unit, cur, max)        UnitFrames:ApplySmoothBarValue(powerBar, cur, max)        local palette = UnitFrames:GetPalette(unitKey, ResolveFrameUnit(frame, unit))        powerBar:SetStatusBarColor(palette.power[1], palette.power[2], palette.power[3], 1)    end    frame.Power = power    if unitKey == "player" then        local classPower = {}        local classContainer = CreateFrame("Frame", nil, frame)        classContainer:SetSize(260, 10)        classContainer:SetPoint("TOPLEFT", frame, "BOTTOMLEFT", 0, -2)        classPower.container = classContainer        classPower.PostVisibility = function(element, isVisible)            local cfg = UnitFrames:GetDB().classBar or {}            element.container:SetShown(cfg.enabled ~= false and isVisible)        end        classPower.PostUpdateColor = function(element, color)            UnitFrames:ApplyClassBarColors(frame, color)        end        for index = 1, 10 do            local bar = CreateFrame("StatusBar", nil, classContainer, "BackdropTemplate")            bar:SetMinMaxValues(0, 1)            bar:SetValue(0)            bar:SetBackdrop({                bgFile = "Interface\\Buttons\\WHITE8x8",                edgeFile = "Interface\\Buttons\\WHITE8x8",                edgeSize = 1,            })            bar:SetBackdropColor(0.05, 0.06, 0.08, 0.9)            bar:SetBackdropBorderColor(0.24, 0.26, 0.32, 0.9)            classPower[index] = bar        end        frame.ClassPower = classPower    end    local name = health:CreateFontString(nil, "OVERLAY")    name:SetPoint("LEFT", health, "LEFT", 4, 0)    name:SetPoint("RIGHT", health, "RIGHT", -56, 0)    name:SetJustifyH("LEFT")    frame.Name = name    local healthValue = health:CreateFontString(nil, "OVERLAY")    healthValue:SetPoint("RIGHT", health, "RIGHT", -4, 0)    healthValue:SetJustifyH("RIGHT")    frame.HealthValue = healthValue    local powerValue = power:CreateFontString(nil, "OVERLAY")    powerValue:SetPoint("RIGHT", power, "RIGHT", -4, 0)    powerValue:SetJustifyH("RIGHT")    frame.PowerValue = powerValue    local auras = CreateFrame("Frame", nil, frame)    auras:SetPoint("BOTTOMLEFT", frame, "TOPLEFT", 0, 6)    auras:SetHeight(18)    auras:SetWidth(160)    auras.initialAnchor = "BOTTOMLEFT"    auras["growth-x"] = "RIGHT"    auras["growth-y"] = "UP"    auras.size = 18    auras.spacing = 2    auras.num = 8    frame.Auras = auras    -- Embedded castbar via oUF Castbar element (all units except player; player uses standalone castbar).    if unitKey ~= "player" then        local castbar = CreateFrame("StatusBar", nil, frame, "BackdropTemplate")        castbar:SetPoint("TOPLEFT", frame, "BOTTOMLEFT", 0, -2)        castbar:SetPoint("TOPRIGHT", frame, "BOTTOMRIGHT", 0, -2)        castbar:SetHeight(12)        castbar:SetMinMaxValues(0, 1)        castbar:SetValue(0)        castbar:SetBackdrop({            bgFile = "Interface\\Buttons\\WHITE8x8",            edgeFile = "Interface\\Buttons\\WHITE8x8",            edgeSize = 1,        })        castbar:SetBackdropColor(0.05, 0.06, 0.08, 0.9)        castbar:SetBackdropBorderColor(0.24, 0.26, 0.32, 0.9)        -- oUF Castbar element sub-widgets        local cbText = castbar:CreateFontString(nil, "OVERLAY")        cbText:SetPoint("LEFT", castbar, "LEFT", 4, 0)        cbText:SetPoint("RIGHT", castbar, "RIGHT", -30, 0)        cbText:SetJustifyH("LEFT")        castbar.Text = cbText        local cbTime = castbar:CreateFontString(nil, "OVERLAY")        cbTime:SetPoint("RIGHT", castbar, "RIGHT", -3, 0)        cbTime:SetJustifyH("RIGHT")        castbar.Time = cbTime        local cbIcon = castbar:CreateTexture(nil, "ARTWORK")        cbIcon:SetSize(12, 12)        cbIcon:SetPoint("RIGHT", castbar, "LEFT", -2, 0)        cbIcon:SetTexCoord(0.08, 0.92, 0.08, 0.92)        castbar.Icon = cbIcon        -- Capture scope for config lookup in callbacks        local capturedCBScope = ResolveCastbarScopeByUnitKey(unitKey)        castbar.PostCastStart = function(cb)            local db = UnitFrames:GetDB()            local castbars = db.castbars or {}            local cfg = castbars[capturedCBScope] or {}            if cfg.enabled == false then cb:Hide() end        end        castbar.PostChannelStart = castbar.PostCastStart        -- Register with oUF        frame.Castbar = castbar    end    EnsureBackdrop(frame)    -- Capture unitKey for aura PostUpdate closures.    local capturedUnitKey = unitKey    -- Drive aura-bar mode updates via oUF's PostUpdate mechanism.    auras.PostUpdate = function()        local auraCfg = UnitFrames:GetAuraConfigFor(capturedUnitKey)        if auraCfg and auraCfg.barMode == true                and frame.AuraBars and frame.AuraBars:IsShown() then            UnitFrames:RefreshAuraBarsForFrame(frame, capturedUnitKey)        end    end    -- Target highlight: colored border that glows when this unit is targeted.    local targetHL = CreateFrame("Frame", nil, frame, "BackdropTemplate")    targetHL:SetPoint("TOPLEFT", frame, "TOPLEFT", -2, 2)    targetHL:SetPoint("BOTTOMRIGHT", frame, "BOTTOMRIGHT", 2, -2)    targetHL:SetFrameLevel(math_max(1, frame:GetFrameLevel() + 3))    targetHL:SetBackdrop({ edgeFile = "Interface\\Buttons\\WHITE8x8", edgeSize = 2 })    targetHL:SetBackdropBorderColor(1, 0.82, 0, 0)    targetHL:Hide()    frame.TwichTargetHighlight = targetHL    -- Mouseover highlight: subtle tint fill on hover.    local hoverHL = CreateFrame("Frame", nil, frame, "BackdropTemplate")    hoverHL:SetAllPoints(frame)    hoverHL:SetFrameLevel(math_max(1, frame:GetFrameLevel() + 2))    hoverHL:SetBackdrop({ bgFile = "Interface\\Buttons\\WHITE8x8" })    hoverHL:SetBackdropColor(1, 1, 1, 0)    hoverHL:Hide()    frame.TwichMouseoverHighlight = hoverHL    frame:SetScript("OnEnter", function(self)        self.isHovering = true        UnitFrames:UpdateUnitHighlights(self)    end)    frame:SetScript("OnLeave", function(self)        self.isHovering = false        UnitFrames:UpdateUnitHighlights(self)    end)    self:ApplyFrameFonts(frame, unitKey)    self:ApplyTextTags(frame, unitKey)    self:ApplySingleFrameSettings(frame, unitKey)endfunction UnitFrames:CreateCastbarFrame()    if self.frames.castbar then        return self.frames.castbar    end    local frame = CreateFrame("StatusBar", "TwichUIUnitFramesPlayerCastbar", UIParent, "BackdropTemplate")    frame:SetMinMaxValues(0, 1)    frame:SetValue(0)    frame:SetBackdrop({        bgFile = "Interface\\Buttons\\WHITE8x8",        edgeFile = "Interface\\Buttons\\WHITE8x8",        edgeSize = 1,    })    frame.bg = frame:CreateTexture(nil, "BACKGROUND")    frame.bg:SetAllPoints(frame)    frame.bg:SetColorTexture(0.05, 0.06, 0.08, 0.9)    frame.icon = frame:CreateTexture(nil, "ARTWORK")    frame.icon:SetPoint("RIGHT", frame, "LEFT", -6, 0)    frame.icon:SetSize(20, 20)    frame.icon:SetTexCoord(0.08, 0.92, 0.08, 0.92)    frame.spellText = frame:CreateFontString(nil, "OVERLAY")    frame.spellText:SetPoint("LEFT", frame, "LEFT", 6, 0)    frame.timeText = frame:CreateFontString(nil, "OVERLAY")    frame.timeText:SetPoint("RIGHT", frame, "RIGHT", -6, 0)    self:ApplyFontObject(frame.spellText, 11)    self:ApplyFontObject(frame.timeText, 10)    self.frames.castbar = frame    self:RegisterLayoutFrame("castbar", frame)    return frameendfunction UnitFrames:RefreshCastbarLayout()    local castbar = self:CreateCastbarFrame()    local db = self:GetDB()    local settings = db.castbar or {}    local layout = self:GetLayoutSettings("castbar")    castbar:ClearAllPoints()    castbar:SetPoint(        layout.point or "BOTTOM",        UIParent,        layout.relativePoint or "BOTTOM",        tonumber(layout.x) or -260,        tonumber(layout.y) or 220    )    castbar:SetSize(Clamp(settings.width or 260, 120, 600), Clamp(settings.height or 20, 10, 60))    castbar:SetShown(settings.enabled ~= false)    castbar:SetScale(Clamp(db.scale or 1, 0.6, 1.6))    castbar:SetAlpha(Clamp(db.frameAlpha or 1, 0.15, 1))    local iconSize = Clamp(settings.iconSize or settings.height or 20, 12, 50)    if castbar.icon then        castbar.icon:SetSize(iconSize, iconSize)        castbar.icon:SetShown(settings.showIcon ~= false)    end    castbar.spellText:ClearAllPoints()    if settings.showIcon ~= false then        castbar.spellText:SetPoint("LEFT", castbar, "LEFT", 6, 0)    else        castbar.spellText:SetPoint("LEFT", castbar, "LEFT", 6, 0)    end    castbar.timeText:ClearAllPoints()    castbar.timeText:SetPoint("RIGHT", castbar, "RIGHT", -6, 0)endfunction UnitFrames:RefreshCastbarStyle()    local castbar = self:CreateCastbarFrame()    local settings = self:GetDB().castbar or {}    local palette = self:GetPalette("player", "player")    local text = self:GetTextConfigFor("player")    local textureName = (settings.texture and settings.texture ~= "") and settings.texture        or ((self:GetDB().texture and self:GetDB().texture ~= "") and self:GetDB().texture or nil)    castbar:SetStatusBarTexture(textureName and GetLSMTexture(textureName) or GetThemeTexture())    castbar.smoothing = self:GetCastbarSmoothingMethod()    if settings.useCustomColor == true and type(settings.color) == "table" then        castbar:SetStatusBarColor(settings.color[1] or 1, settings.color[2] or 1, settings.color[3] or 1, settings.color[4] or 1)    else        castbar:SetStatusBarColor(palette.cast[1], palette.cast[2], palette.cast[3], 1)    end    castbar:SetBackdropColor(palette.background[1], palette.background[2], palette.background[3], 0.9)    castbar:SetBackdropBorderColor(palette.border[1], palette.border[2], palette.border[3], 0.9)    castbar.spellText:SetShown(settings.showSpellText ~= false)    castbar.timeText:SetShown(settings.showTimeText ~= false)    self:ApplyFontObject(castbar.spellText, Clamp(settings.spellFontSize or 11, 6, 24), text.fontName, text)    self:ApplyFontObject(castbar.timeText, Clamp(settings.timeFontSize or 10, 6, 24), text.fontName, text)endfunction UnitFrames:UpdateCastbarElapsed()    local state = self._castbarState    local castbar = self.frames.castbar    if not state or not castbar then        return    end    local duration = math_max(0.001, state.endTime - state.startTime)    local now = GetTimePreciseSec()    if now >= state.endTime then        self:ApplyCastbarValue(castbar, duration, duration)        castbar.timeText:SetText("0.0")        castbar:Hide()        self._castbarState = nil        return    end    local elapsed = now - state.startTime    local timeValue = state.reverse and (duration - elapsed) or elapsed    self:ApplyCastbarValue(castbar, timeValue, duration)    castbar.timeText:SetText(string.format("%.1f", state.endTime - now))endfunction UnitFrames:BeginCastbar(name, icon, startMS, endMS, reverse)    local castbar = self.frames.castbar    if not castbar then        return    end    local startSec = (tonumber(startMS) or 0) / 1000    local endSec = (tonumber(endMS) or 0) / 1000    if startSec <= 0 or endSec <= startSec then        return    end    castbar.spellText:SetText(name or "Casting")    if castbar.icon then        castbar.icon:SetTexture(icon or 136243)    end    castbar:SetMinMaxValues(0, 1)    -- Seed the smooth interpolation with the correct start position.    local duration = math_max(0.001, (tonumber(endMS) or 0) / 1000 - (tonumber(startMS) or 0) / 1000)    self:ApplyCastbarValue(castbar, reverse and duration or 0, duration)    castbar:Show()    self._castbarState = {        startTime = startSec,        endTime = endSec,        reverse = reverse == true,    }endfunction UnitFrames:StopCastbar()    local castbar = self.frames.castbar    if castbar then        castbar:Hide()    end    self._castbarState = nilendfunction UnitFrames:HandlePlayerCastEvent(event, unit, castGUID, spellID)    if unit and unit ~= "player" then        return    end    if event == "UNIT_SPELLCAST_START" then        local name, _, texture, startMS, endMS = UnitCastingInfo("player")        if name then            self:BeginCastbar(name, texture, startMS, endMS, false)        end        return    end    if event == "UNIT_SPELLCAST_CHANNEL_START" then        local name, _, texture, startMS, endMS = UnitChannelInfo("player")        if name then            self:BeginCastbar(name, texture, startMS, endMS, true)        end        return    endfunction UnitFrames:OnInitialize()    local db = self:GetDB()    db.enabled = db.enabled ~= false    self:RegisterDebugSource()endfunction UnitFrames:OnEnable()    self:RegisterDebugSource()    if not self:SpawnFrames() thenendfunction UnitFrames:SpawnSingleFrame(oUF, unit, key)    local frame = oUF:Spawn(unit, "TwichUIUF_" .. key)    frame.key = key    self.frames[key] = frame    self:RegisterLayoutFrame(key, frame)    return frameendfunction UnitFrames:SpawnBossFrames(oUF)    if self.bossAnchor then        return    end    self.bossAnchor = CreateFrame("Frame", "TwichUIUF_BossAnchor", UIParent)    self.bossAnchor:SetSize(260, 220)    self:RegisterLayoutFrame("boss", self.bossAnchor)    for index = 1, 5 do        local key = "boss" .. index        local frame = self:SpawnSingleFrame(oUF, key, key)        if index == 1 then            frame:SetPoint("TOP", self.bossAnchor, "TOP", 0, 0)        else            frame:SetPoint("TOP", self.frames["boss" .. (index - 1)], "BOTTOM", 0, -8)        end    endendfunction UnitFrames:SpawnHeaders(oUF)    if self.headers.party then        return    end    self.headers.party = oUF:SpawnHeader(        "TwichUIUF_PartyHeader",        nil,        "showParty", true,        "showPlayer", true,        "showSolo", false,        "yOffset", -8,        "point", "TOP"    )    self.headers.raid = oUF:SpawnHeader(        "TwichUIUF_RaidHeader",        nil,        "showRaid", true,        "showParty", false,        "showSolo", false,        "groupBy", "GROUP",        "groupingOrder", "1,2,3,4,5,6,7,8",        "yOffset", -6,        "point", "TOP",        "maxColumns", 8,        "unitsPerColumn", 5    )    self.headers.tank = oUF:SpawnHeader(        "TwichUIUF_TankHeader",        nil,        "showRaid", true,        "showParty", false,        "showSolo", false,        "groupFilter", "MAINTANK,MAINASSIST",        "yOffset", -6,        "point", "TOP",        "maxColumns", 1,        "unitsPerColumn", 8    )    self:RegisterLayoutFrame("party", self.headers.party)    self:RegisterLayoutFrame("raid", self.headers.raid)    self:RegisterLayoutFrame("tank", self.headers.tank)endfunction UnitFrames:EnsureStyle()    local oUF = GetOUF()    if not oUF then        return false    end    if self.styleRegistered then        return true    end    oUF:RegisterStyle(STYLE_NAME, function(frame)        UnitFrames:StyleFrame(frame)    end)    self.styleRegistered = true    return trueendfunction UnitFrames:SpawnFrames()    local oUF = GetOUF()    if not oUF then        return false    end    if not self:EnsureStyle() then        return false    end    oUF:SetActiveStyle(STYLE_NAME)    oUF:Factory(function(factory)        if UnitFrames.frames.player then            if not UnitFrames.headers.party then                UnitFrames:SpawnHeaders(factory)            end            UnitFrames:RefreshAllFrames()            return        end        UnitFrames:SpawnSingleFrame(factory, "player", "player")        UnitFrames:SpawnSingleFrame(factory, "target", "target")        UnitFrames:SpawnSingleFrame(factory, "targettarget", "targettarget")        UnitFrames:SpawnSingleFrame(factory, "focus", "focus")        UnitFrames:SpawnSingleFrame(factory, "pet", "pet")        UnitFrames:SpawnBossFrames(factory)        UnitFrames:SpawnHeaders(factory)        UnitFrames:CreateCastbarFrame()        UnitFrames:RefreshAllFrames()    end)    return trueendfunction UnitFrames:OnInitialize()    local db = self:GetDB()    db.enabled = db.enabled ~= falseendfunction UnitFrames:OnEnable()    if not self:SpawnFrames() then        T:Print("UnitFrames: oUF is unavailable. Ensure Libraries/oUF/oUF.xml is loaded.")        return    end    self:RegisterMessage("TWICH_THEME_CHANGED", "OnThemeChanged")    self:RegisterMessage("TWICH_CONFIG_RESTORED", "OnConfigRestored")    self:RegisterEvent("UNIT_SPELLCAST_START", "HandlePlayerCastEvent")    self:RegisterEvent("UNIT_SPELLCAST_STOP", "HandlePlayerCastEvent")    self:RegisterEvent("UNIT_SPELLCAST_FAILED", "HandlePlayerCastEvent")    self:RegisterEvent("UNIT_SPELLCAST_INTERRUPTED", "HandlePlayerCastEvent")    self:RegisterEvent("UNIT_SPELLCAST_CHANNEL_START", "HandlePlayerCastEvent")    self:RegisterEvent("UNIT_SPELLCAST_CHANNEL_STOP", "HandlePlayerCastEvent")    self:RegisterEvent("PLAYER_TARGET_CHANGED", "OnTargetChanged")    self:RegisterEvent("UPDATE_MOUSEOVER_UNIT", "OnMouseoverChanged")    self:RegisterEvent("GROUP_ROSTER_UPDATE", "RefreshAllFrames")    self:RegisterEvent("PLAYER_ENTERING_WORLD", "RefreshAllFrames")    self.ticker = C_Timer.NewTicker(0.05, function()        if UnitFrames._castbarState then            UnitFrames:UpdateCastbarElapsed()        end        if UnitFrames._queuedRefresh and not InCombatLockdown() then            UnitFrames._queuedRefresh = false            UnitFrames:RefreshAllFrames()        end    end)    self:RefreshAllFrames()endfunction UnitFrames:OnDisable()    self:UnregisterMessage("TWICH_THEME_CHANGED")    self:UnregisterMessage("TWICH_CONFIG_RESTORED")    self:UnregisterAllEvents()    if self.ticker then        self.ticker:Cancel()        self.ticker = nil    end    for _, frame in pairs(self.frames) do        if frame then            self:StopSmoothBar(frame.Health)            self:StopSmoothBar(frame.Power)            frame:Hide()        end    end    for _, header in pairs(self.headers) do        if header then            header:Hide()        end    end    for _, preview in pairs(self.previewFrames) do        if preview then            preview:Hide()        end    end    for _, mover in pairs(self.movers) do        if mover then            mover:Hide()        end    end    self:StopCastbar()endfunction UnitFrames:SetTestMode(enabled)    local db = self:GetDB()    db.testMode = enabled == true    self:RefreshAllFrames()endfunction UnitFrames:SetFrameLock(locked)    local db = self:GetDB()    db.lockFrames = locked == true    self:UpdateMovers()endfunction UnitFrames:RefreshFromOptions()    if self:IsEnabled() then        self:RefreshAllFrames()    endend